// Exhaustive authored guides layered over the compact initial content catalogue.
window.DOC_GUIDES.models = {title:"Domain models",description:"Construct the immutable vocabulary used by every QuantVolt workflow.",body:`
  <p>QuantVolt models are frozen value objects. Construction validates their invariants, methods never mutate caller state, and serializable models round-trip through plain dictionaries.</p>
  <h2 id="commodities">Commodities and hubs</h2>${codeBlock(`import quantvolt as qv\n\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nprint(ttf.commodity_id, ttf.hub.exchange, ttf.price_unit)\n\ncustom_hub = qv.Hub(\n    hub_id="DK1",\n    exchange="NORD_POOL",\n    price_unit="EUR/MWh",\n)\ncustom_power = qv.CommodityConfig(\n    commodity_id="DK1_POWER",\n    price_unit="EUR/MWh",\n    hub=custom_hub,\n)\nregistry = qv.merge_commodities({"DK1_POWER": custom_power})`, `TTF ICE_ENDEX EUR/MWh\nDK1_POWER added\nBuilt-in definitions preserved`)}
  <table><thead><tr><th>Object</th><th>Role</th><th>Important behavior</th></tr></thead><tbody><tr><td><code>Hub</code></td><td>Delivery/location identity</td><td>Stable ID, name and country/area</td></tr><tr><td><code>CommodityConfig</code></td><td>Commodity identity</td><td>Stable ID, display name and hub</td></tr><tr><td><code>resolve_commodity</code></td><td>Registry lookup</td><td>Raises for unknown IDs</td></tr><tr><td><code>merge_commodities</code></td><td>Registry extension</td><td>Caller entry wins on ID collision</td></tr></tbody></table>
  <h2 id="periods">Delivery periods, schedules and intervals</h2>${codeBlock(`from datetime import UTC, datetime\n\ndec = qv.DeliveryPeriod(2026, 12)\nq1 = qv.DeliverySchedule((\n    qv.DeliveryPeriod(2027, 1),\n    qv.DeliveryPeriod(2027, 2),\n    qv.DeliveryPeriod(2027, 3),\n))\ninterval = qv.PowerDeliveryInterval(\n    start_utc=datetime(2026, 12, 1, 0, 0, tzinfo=UTC),\n    end_utc=datetime(2026, 12, 1, 0, 15, tzinfo=UTC),\n)\nprint(dec.first_day, dec.last_day, len(q1.periods))`, `2026-12-01 2026-12-31 3\ninterval duration  15 minutes`)}
  <p><code>DeliveryPeriod</code> is one calendar month. <code>DeliverySchedule</code> requires strictly increasing, non-duplicate periods. <code>PowerDeliveryInterval</code> requires timezone-aware UTC endpoints with end strictly after start.</p>
  <h2 id="curves-models">Forward and discount curves</h2>${codeBlock(`from datetime import date\n\ncurve = qv.ForwardCurve(\n    commodity=ttf,\n    market_date=date(2026, 7, 15),\n    nodes=(\n        qv.CurveNode(qv.DeliveryPeriod(2026, 11), 33.33, "interpolated"),\n        qv.CurveNode(qv.DeliveryPeriod(2026, 12), 36.85, "observed"),\n    ),\n)\ndiscount = qv.DiscountCurve(\n    reference_date=date(2026, 7, 15),\n    tenors=(date(2026, 7, 16), date(2027, 12, 31)),\n    factors=(1.0, 0.96),\n)\nprint(curve.price_at(qv.DeliveryPeriod(2026, 12)))\nprint(round(discount.discount_factor(date(2026, 12, 31)), 6))`, `36.85 EUR/MWh\n0.986731 discount factor`)}
  <h2 id="volatility-models">Volatility tenors and surfaces</h2><p><code>Moneyness</code> classifies option strikes, <code>VolatilityTenor</code> binds a delivery period and moneyness bucket, and <code>VolatilitySurface</code> stores validated annualized volatilities. Surface lookup never silently extrapolates an uncovered tenor.</p>
  <div class="result-grid"><div><small>Volatility input</small><strong>0.55</strong></div><div><small>Meaning</small><strong>55% annualized</strong></div><div><small>Missing bucket</small><strong>MissingTenorError</strong></div></div>
  <h2 id="instruments-models">Financial instruments</h2>${codeBlock(`period = qv.DeliveryPeriod(2026, 12)\nfuture = qv.FuturesContract(\n    ttf, period, contract_price=35.0, notional=5_000.0\n)\nforward = qv.ForwardContract(\n    ttf, period, contract_price=34.5, notional=5_000.0,\n    settlement_type=qv.SettlementType.PHYSICAL,\n    counterparty="Utility BV",\n)\nswap = qv.SwapContract(\n    commodity=ttf, fixed_rate=34.0,\n    floating_index="TTF_MONTH_AHEAD", notional=2_000.0,\n    schedule=qv.DeliverySchedule((period,)),\n)`, `FuturesContract  financial · exchange traded\nForwardContract  physical · counterparty Utility BV\nSwapContract     payer fixed · one period`)}
  <p><code>SettlementType</code> distinguishes physical and financial settlement. <code>RiskType</code> supplies execution, basis, liquidity, credit, storage and transmission classifications. Negative contract prices and fixed rates are valid; notionals must be positive.</p>
  <h2 id="physical-models">Physical and structured contracts</h2><table><thead><tr><th>Type</th><th>Defines</th></tr></thead><tbody><tr><td><code>PlantConfig</code></td><td>Heat rate, variable O&amp;M, emissions intensity and gas/coal fuel type</td></tr><tr><td><code>PpaContract</code></td><td>Zone, fixed price, interval, volume basis and settlement type</td></tr><tr><td><code>PowerHedgeContract</code></td><td>Floor, cap, swap or collar with direction, volume, strikes and premium</td></tr><tr><td><code>TransmissionRight</code></td><td>Power route, direction, tariff, loss and capacity</td></tr><tr><td><code>PipelineRight</code></td><td>Gas route with the same transport economics</td></tr></tbody></table>
  <h2 id="serialization-models">Serialization and immutability</h2>${codeBlock(`payload = curve.to_dict()\nrestored = qv.ForwardCurve.from_dict(payload)\nassert restored == curve\n\nfrom quantvolt.testing import assert_input_unchanged\npriced = assert_input_unchanged(\n    qv.price_futures, future, curve,\n    date(2026, 7, 15), discount,\n)`, `✓ ForwardCurve exact dictionary round trip\n✓ pricing left every caller input unchanged`)}
`};

window.DOC_GUIDES.numerics = {title:"Numerical kernels",description:"Use the pure mathematical layer directly with floats and NumPy arrays.",body:`
  <p><code>quantvolt.numerics</code> contains orchestration-free kernels. High-level pricers call these functions after domain validation; direct callers are responsible for respecting the documented numerical domains.</p>
  <h2 id="black76-kernels">Black–76 pricing and Greeks</h2>${codeBlock(`from quantvolt.numerics import (\n    black76_greeks, black76_implied_vol, black76_price,\n)\n\npremium = black76_price(\n    "call", forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n)\ngreeks = black76_greeks(\n    "call", forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n)\nrecovered = black76_implied_vol(\n    "call", premium, forward=36.85, strike=38.0,\n    time_to_expiry=0.4, discount_factor=0.99,\n)`, `unit premium       4.5663\nimplied volatility 0.5500\ndelta               0.5288\ngamma               0.0293`)}
  <h2 id="vol-conventions">Black-76 vs Bachelier: two different volatilities</h2><p>Black-76 volatility is dimensionless: a lognormal, annualized rate (e.g. <code>0.55</code> means 55% per year). Bachelier volatility is an absolute price-rate: normal (arithmetic) volatility in price units per square-root year (e.g. EUR/MWh per &radic;yr). They are not interchangeable &mdash; passing a lognormal vol as <code>normal_sigma</code>, or a normal vol as Black-76 <code>sigma</code>, is a silent unit error, not a rounding difference. QuantVolt never converts between them for you.</p>${codeBlock(`F = K = 40.0; T = 0.5; DF = 0.99\n\n# Black-76: dimensionless lognormal vol.\nblack = qv.price_vanilla_option(qv.VanillaOptionRequest(\n    option_type="call", strike=K, notional=1.0, forward=F,\n    sigma=0.55, time_to_expiry=T, discount_factor=DF,\n))\n\n# Bachelier: absolute normal vol in EUR/MWh per sqrt-year.\n# For an ATM option the two match when sigma_N ~ sigma_LN * F = 0.55 * 40 = 22.0.\nbachelier = qv.price_bachelier_option(qv.BachelierOptionRequest(\n    option_type="call", strike=K, notional=1.0, forward=F,\n    normal_sigma=22.0, time_to_expiry=T, discount_factor=DF,\n))`, `Black-76   (sigma = 0.55, dimensionless)          premium  6.1055\nBachelier  (normal_sigma = 22.0 EUR/MWh/sqrt-yr)  premium  6.1440\nBachelier  (0.55 mis-passed as normal_sigma)      premium  0.1536   # unit error`)}<p>The two pricers agree to within the ATM lognormal/normal conversion (6.11 vs 6.14). Feeding the dimensionless <code>0.55</code> straight into <code>normal_sigma</code> returns <code>0.1536</code> &mdash; roughly 40&times; too small.</p>
  <h2 id="model-selection">Choosing a pricing model</h2><table><thead><tr><th>Model</th><th>Entry point</th><th>Use when</th><th>Domain constraint</th></tr></thead><tbody>
    <tr><td>Black-76</td><td><code>price_vanilla_option</code> / <code>black76_price</code></td><td>Single European option on one positive forward; lognormal vol available</td><td>forward &gt; 0, strike &gt; 0, sigma &gt; 0; raises <code>ValidationError</code> otherwise</td></tr>
    <tr><td>Bachelier</td><td><code>price_bachelier_option</code> / <code>bachelier_price</code></td><td>Forward or strike may be zero or negative (power, oil since 2020); normal vol available</td><td>forward, strike finite (any sign); <code>normal_sigma</code> &gt; 0 &mdash; absolute price-rate, not lognormal</td></tr>
    <tr><td>Margrabe</td><td><code>margrabe</code> (via <code>price_spread_option</code> at <code>strike=0</code>)</td><td>Exact zero-strike spread (exchange) option on two positive forwards</td><td>Exact only at strike = 0; both forwards &gt; 0</td></tr>
    <tr><td>Kirk</td><td><code>kirk</code> (via <code>price_spread_option</code> at <code>strike != 0</code>)</td><td>Non-zero-strike spread option; accepted approximation</td><td>Requires <code>forward2 + strike &gt; 0</code>; raises <code>ValidationError</code> otherwise</td></tr>
    <tr><td>Turnbull-Wakeman</td><td><code>turnbull_wakeman</code> (via <code>price_asian</code>)</td><td>Arithmetic-average Asian; fast moment-matched closed form</td><td>forward &gt; 0, strike &gt; 0 (matched to Black-76); approximation</td></tr>
    <tr><td>Monte Carlo</td><td><code>asian_monte_carlo</code> (via <code>price_asian</code>, <code>method="monte_carlo"</code>)</td><td>Path-dependent payoffs, or a cross-check for the closed forms; reports a standard error</td><td>Seeded and deterministic; interpret premium together with its standard error</td></tr>
  </tbody></table><p>Margrabe is the exact zero-strike case; <code>price_spread_option</code> dispatches to Margrabe at <code>strike == 0.0</code> and to Kirk otherwise. Kirk is defined only while the shifted short leg <code>forward2 + strike</code> stays strictly positive.</p>
  <h2 id="spread-kernels">Kirk and Margrabe spread models</h2>${codeBlock(`from quantvolt.numerics import kirk, margrabe\n\nkirk_value = kirk(\n    forward1=92.0, forward2=73.7, strike=4.0,\n    sigma1=0.38, sigma2=0.52, rho=0.61,\n    time_to_expiry=0.5, discount_factor=0.98,\n)\nexchange_value = margrabe(\n    forward1=92.0, forward2=73.7,\n    sigma1=0.38, sigma2=0.52, rho=0.61,\n    time_to_expiry=0.5, discount_factor=0.98,\n)`, `Kirk, strike 4.0     7.842\nMargrabe, strike 0  10.964`)}<p>Kirk requires <code>forward2 + strike &gt; 0</code>. At zero strike its shifted-leg construction reduces to the exact Margrabe exchange-option form.</p>
  <h2 id="exotic-kernels">Asian, barrier and lookback kernels</h2><table><thead><tr><th>Kernel</th><th>Method</th><th>Output</th></tr></thead><tbody><tr><td><code>turnbull_wakeman</code></td><td>Arithmetic-average approximation</td><td>Premium</td></tr><tr><td><code>kemna_vorst</code></td><td>Geometric-average analytic</td><td>Premium</td></tr><tr><td><code>asian_monte_carlo</code></td><td>Native seeded simulation</td><td>Premium, standard error</td></tr><tr><td><code>barrier_analytic</code></td><td>Up/down, in/out analytic</td><td>Premium</td></tr><tr><td><code>lookback_fixed</code></td><td>Fixed-strike lookback</td><td>Premium</td></tr><tr><td><code>lookback_floating</code></td><td>Floating-strike lookback</td><td>Premium</td></tr></tbody></table>${codeBlock(`from quantvolt.numerics import asian_monte_carlo\n\npremium, stderr = asian_monte_carlo(\n    forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n    averaging_points=12, option_type="call",\n    geometric=False, seed=7, path_count=50_000,\n)`, `premium         2.623289\nstandard error  0.021925\nseed            7\npaths           50,000`)}
  <h2 id="simulation-kernels">Covariance and correlated forwards</h2>${codeBlock(`import numpy as np\nfrom quantvolt.numerics import build_covariance, simulate_correlated_forwards\n\nvols = np.array([0.55, 0.38])\ncorrelation = np.array([[1.0, 0.61], [0.61, 1.0]])\ncovariance = build_covariance(vols, correlation, dt=0.5)\nz0 = np.log(np.array([36.85, 92.0]))\ndrift = -0.5 * np.diag(covariance)\npaths = simulate_correlated_forwards(\n    z0=z0, drift=drift, cov=covariance,\n    steps=1, path_count=10_000, seed=42,\n)\nprint(covariance.shape, paths.shape)`, `(2, 2) (10000, 2, 2)\nsame inputs, seed, QuantVolt version, architecture and native build → identical log-forward paths`)}
  <h2 id="interpolation-kernels">Interpolation</h2>${codeBlock(`import numpy as np\nfrom quantvolt.numerics import cubic_spline, piecewise_flat, piecewise_linear\n\nx = np.array([0.0, 2.0, 5.0, 8.0])\ny = np.array([31.4, 36.85, 34.1, 37.2])\ntarget = np.array([1.0, 3.0, 4.0])\n\nflat = piecewise_flat(x, y, target)\nlinear = piecewise_linear(x, y, target)\nsmooth = cubic_spline(x, y, target)`, `target  flat    linear  cubic\n1.0     31.40   34.12   34.79\n3.0     36.85   35.93   36.69\n4.0     36.85   35.02   35.29`)}<p>Piecewise flat requires one quote, linear requires two, and cubic spline requires four. The <code>INTERPOLATION_METHODS</code> registry maps the supported method names to these kernels.</p>
  <h2 id="root-kernels">Root finding and finite differences</h2>${codeBlock(`from quantvolt.numerics import brent_root, finite_difference_bump\n\nroot = brent_root(lambda x: x * x - 2.0, a=0.0, b=2.0)\nslope = finite_difference_bump(lambda x: x * x, x=3.0, bump=1e-4)`, `root of x² − 2  1.41421356\nderivative at 3  6.00000000`)}<p><code>brent_root</code> requires a sign-changing bracket. Finite differences require a positive bump; callers should test bump sensitivity for ill-conditioned functions.</p>
  <h2 id="measure-kernels">Physical and risk-neutral measures</h2><p><code>PriceOfRiskKind</code> distinguishes market and corporate prices of risk. <code>DriftKind</code> labels physical P and risk-neutral Q drift assumptions. <code>price_of_risk</code>, <code>tradable_price_of_risk</code> and <code>risk_adjusted_drift</code> make the measure transformation explicit; <code>require_physical_drift</code> rejects a Q-measure drift where a physical forecast is required.</p>
`};

window.DOC_GUIDES.curves = {title:"Forward-curve construction",description:"Build gap-filled monthly curves and preserve quote provenance, repricing diagnostics and carry warnings.",body:`
  <h2 id="construction">Complete market setup</h2>${codeBlock(`from datetime import date\nimport quantvolt as qv\n\nmarket_date = date(2026, 7, 15)\nttf = qv.BUILT_IN_COMMODITIES["TTF"]\nobserved = [\n    qv.InstrumentPriceRecord(\n        "TTF-OCT26", ttf, qv.DeliveryPeriod(2026, 10), 31.40\n    ),\n    qv.InstrumentPriceRecord(\n        "TTF-DEC26", ttf, qv.DeliveryPeriod(2026, 12), 36.85\n    ),\n    qv.InstrumentPriceRecord(\n        "TTF-MAR27", ttf, qv.DeliveryPeriod(2027, 3), 34.10\n    ),\n]\nresult = qv.CurveBuilder().build(\n    commodity=ttf, market_date=market_date,\n    instruments=observed, interpolation="piecewise_linear",\n    storage_cost=0.50,\n)\ncurve = result.curve`, `OCT 26  31.40  observed\nNOV 26  34.12  interpolated\nDEC 26  36.85  observed\nJAN 27  35.93  interpolated\nFEB 27  35.02  interpolated\nMAR 27  34.10  observed`, "python", miniCurve())}
  <p><code>CurveBuildResult</code> keeps three outputs together: the constructed <code>ForwardCurve</code>, carry/arbitrage warnings and one repricing residual per observed instrument.</p>
  <h2 id="interpolation">Choose an interpolation policy</h2><table><thead><tr><th>Method</th><th>Minimum observations</th><th>Behavior</th></tr></thead><tbody><tr><td><code>piecewise_flat</code></td><td>1</td><td>Holds the most recent quote constant between observations</td></tr><tr><td><code>piecewise_linear</code></td><td>2</td><td>Connects observed monthly prices with straight segments</td></tr><tr><td><code>cubic_spline</code></td><td>4</td><td>Smooth cubic interpolation through a well-observed term structure</td></tr></tbody></table>${codeBlock(`for method in ("piecewise_flat", "piecewise_linear", "cubic_spline"):\n    built = qv.CurveBuilder().build(\n        ttf, market_date, four_or_more_quotes, interpolation=method\n    )\n    print(method, built.curve.price_at(qv.DeliveryPeriod(2026, 11)))`, `piecewise_flat    31.400\npiecewise_linear  34.125\ncubic_spline      35.018\n(printed at 3 decimals; tables elsewhere round to 2)`)}
  <div class="admonition note"><b>Policy stays visible</b><p>Every generated <code>CurveNode</code> has status <code>interpolated</code>; observed quotes remain <code>observed</code>. Downstream reports can distinguish market data from modeling assumptions.</p></div>
  <h2 id="arbitrage">Cost-of-carry checks</h2>${codeBlock(`warnings = qv.check_arbitrage(curve, storage_cost=0.50)\nfor warning in warnings:\n    print(warning.periods)\nprint("warning count", len(warnings))`, `(Dec-26, Jan-27)\n(Jan-27, Feb-27)\n(Feb-27, Mar-27)\nwarning count 3`)}<p>A consecutive pair is flagged when the later price is below the earlier price by more than monthly storage cost can explain. Here each 0.9167 monthly decline exceeds the 0.50 carry assumption. <code>ArbitrageChecker</code> returns <code>ArbitrageWarning</code> values; it does not silently alter the curve.</p>
  <h2 id="errors-curves">Validation boundaries</h2>${codeBlock(`try:\n    qv.CurveBuilder().build(\n        ttf, market_date, observed[:1], interpolation="cubic_spline"\n    )\nexcept qv.InsufficientDataError as exc:\n    print(exc)`, `InsufficientDataError\ncubic_spline requires at least 4 observed instruments`)}<p>Duplicate periods, non-finite prices, unknown interpolation methods and invalid storage cost fail before construction.</p>
  <h2 id="models">Stochastic models after construction</h2><p>A deterministic market curve is the initial term structure for <code>SchwartzSmithParams</code> and <code>MultifactorForwardModel</code>. Those models simulate factor-driven forward evolution; they do not replace quote interpolation or provenance.</p>
`};

// Fill the contract-family sections that were intentionally compact in the first pricing draft.
window.DOC_GUIDES.pricing.body = window.DOC_GUIDES.pricing.body
  .replace(
    `<h2 id="caps-floors">Caps and floors</h2><p><code>price_cap_floor</code> prices a strip over multiple forwards. The result exposes aggregate premium and the contribution of every caplet or floorlet, so tenor-level attribution is preserved.</p>`,
    `<h2 id="caps-floors">Caps and floors</h2><p>A cap is a strip of calls; a floor is a strip of puts. Each period retains its own forward, volatility, expiry, discount factor and notional.</p>${codeBlock(`caplets = tuple(\n    qv.VanillaOptionRequest(\n        option_type="call", strike=38.0, notional=1_000.0,\n        forward=forward, sigma=sigma,\n        time_to_expiry=expiry, discount_factor=df,\n    )\n    for forward, sigma, expiry, df in (\n        (36.85, 0.55, 0.40, 0.990),\n        (35.93, 0.52, 0.48, 0.986),\n        (35.02, 0.50, 0.56, 0.982),\n    )\n)\ncap = qv.price_cap_floor(qv.CapFloorRequest(\n    option_type="cap", strike=38.0,\n    notional=1_000.0, caplets=caplets,\n))\nprint(cap.premium)\nprint([item.premium for item in cap.per_period])`, `aggregate premium  €11,924\nperiod premiums    €4,566 · €3,921 · €3,437\nperiod count       3`)}<p><code>CapFloorResult.premium</code> is exactly the sum of <code>per_period</code> premiums, and aggregate Greeks are exact elementwise sums. A strip may contain at most 120 periods.</p>`
  )
  .replace(
    `<h2 id="exotics">Asian, barrier and lookback options</h2><table><thead><tr><th>Contract</th><th>Available method</th><th>Entry point</th></tr></thead><tbody><tr><td>Arithmetic/geometric Asian</td><td>Turnbull–Wakeman, Kemna–Vorst, seeded Monte Carlo</td><td><code>price_asian</code></td></tr><tr><td>Knock-in / knock-out barrier</td><td>Analytic barrier formula</td><td><code>price_barrier</code></td></tr><tr><td>Fixed/floating lookback</td><td>Analytic lookback formula</td><td><code>price_lookback</code></td></tr></tbody></table>`,
    `<h2 id="exotics">Asian, barrier and lookback options</h2><table><thead><tr><th>Contract</th><th>Available method</th><th>Entry point</th></tr></thead><tbody><tr><td>Arithmetic/geometric Asian</td><td>Turnbull–Wakeman, Kemna–Vorst, seeded Monte Carlo</td><td><code>price_asian</code></td></tr><tr><td>Knock-in / knock-out barrier</td><td>Reiner–Rubinstein analytic</td><td><code>price_barrier</code></td></tr><tr><td>Fixed/floating lookback</td><td>Analytic lookback formula</td><td><code>price_lookback</code></td></tr></tbody></table>${codeBlock(`asian = qv.price_asian(qv.AsianOptionRequest(\n    option_type="call", averaging="arithmetic",\n    strike=38.0, forward=36.85, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n    method="monte_carlo", seed=7, path_count=50_000,\n))\nbarrier = qv.price_barrier(qv.BarrierOptionRequest(\n    option_type="call", barrier_type="up_out",\n    strike=38.0, barrier=55.0, forward=36.85,\n    sigma=0.55, time_to_expiry=0.4, discount_factor=0.99,\n))\nlookback = qv.price_lookback(qv.LookbackOptionRequest(\n    option_type="call", strike_type="fixed", strike=38.0,\n    forward=36.85, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n))`, `Asian MC       premium + standard error + Greeks\nUp-and-out     premium + finite-difference Greeks\nFixed lookback premium + finite-difference Greeks`)}<p>An up barrier must be strictly above the forward and a down barrier strictly below it. Floating lookbacks require <code>strike=None</code>; fixed lookbacks require a positive strike.</p>`
  )
  .replace(
    `<h2 id="tolling">Tolling agreements</h2><p><code>price_tolling_agreement</code> values a thermal plant as a strip of clean-spread options. It requires power, fuel and EUA curves, a volatility surface, a correlation matrix, plant conversion parameters, schedule and discount curve.</p>`,
    `<h2 id="tolling">Tolling agreements</h2><p>A tolling agreement is valued as one clean-spread option per schedule period. Every physical conversion and market dependency is explicit.</p>${codeBlock(`import numpy as np\n\nperiod = qv.DeliveryPeriod(2026, 12)\nplant = qv.PlantConfig(\n    heat_rate=2.0, variable_om_cost=3.5,\n    emissions_intensity=0.37, fuel_type="gas",\n)\nschedule = qv.DeliverySchedule((period,))\npower_vol = qv.VolatilitySurface(\n    commodity=power,\n    tenors=(qv.VolatilityTenor(period, 0.38),),\n)\nfuel_vol = qv.VolatilitySurface(\n    commodity=ttf,\n    tenors=(qv.VolatilityTenor(period, 0.52),),\n)\ncorrelation = np.array([\n    [1.00, 0.61, 0.25],\n    [0.61, 1.00, 0.18],\n    [0.25, 0.18, 1.00],\n])\nresult = qv.price_tolling_agreement(\n    plant, power_curve, ttf_curve, eua_curve,\n    power_vol, correlation, schedule, discount_curve,\n    capacity=1_000.0, fuel_sigma=fuel_vol,\n)`, `TollingResult\n  NPV             per-period option value sum\n  intrinsic value immediate clean-spread value\n  time value      NPV − intrinsic\n  deltas          power · fuel · EUA`)}<p>Curve, surface and discount coverage are validated for every period before pricing. Correlation must be square, symmetric, unit-diagonal and have off-diagonals strictly inside (−1, 1).</p>`
  )
  .replace(
    `<h2 id="rights">Transmission and pipeline rights</h2><p><code>value_transport_right</code> values directional or bidirectional transport after tariffs, losses and capacity constraints. Both <code>TransmissionRight</code> and <code>PipelineRight</code> retain route and direction metadata.</p>`,
    `<h2 id="rights">Transmission and pipeline rights</h2>${codeBlock(`period = qv.DeliveryPeriod(2026, 12)\nright = qv.TransmissionRight(\n    origin="EPEX_DE", destination="EPEX_NL",\n    tariff=2.50, quantity=100.0,\n    schedule=qv.DeliverySchedule((period,)),\n    direction=qv.TransportDirection.A_TO_B,\n    loss=0.03, capacity=90.0,\n)\nresult = qv.value_transport_right(\n    right, de_power_curve, nl_power_curve, discount_curve,\n    vols=(0.38, 0.35), correlation=0.72,\n)`, `available quantity  100.0 MWh\ncapacity bound       90.0 MWh\ndelivered after loss 87.3 MWh\nvalue                 discounted optional spread payoff`)}<p><code>B_TO_A</code> reverses the economic route. <code>BIDIRECTIONAL</code> values both directions and uses <code>reverse_tariff</code> when supplied. <code>PipelineRight</code> shares the transport-value formula but remains a distinct gas-transport type.</p>`
  )
  .replace(
    `<h2 id="implied-vol">Implied volatility and surfaces</h2><p>Recover Black–76 volatility from premiums with <code>implied_vol</code>, classify moneyness, estimate cumulative historical volatility and construct a <code>VolatilitySurface</code> from tenor/moneyness quotes.</p>`,
    `<h2 id="implied-vol">Implied volatility and surfaces</h2>${codeBlock(`from quantvolt.pricing import OptionQuote\n\nperiod = qv.DeliveryPeriod(2026, 12)\nquote = OptionQuote(\n    period=period, option_type="call", strike=38.0,\n    premium=4.566311, forward=36.85,\n    time_to_expiry=0.4, discount_factor=0.99,\n)\nresult = qv.implied_vol(\n    quote.option_type, quote.premium, quote.forward, quote.strike,\n    quote.time_to_expiry, quote.discount_factor,\n)\nsurface = qv.build_volatility_surface(\n    [quote, *other_tenor_quotes], commodity=ttf,\n    interpolation="linear",\n)\nprint(result.implied_vol, result.moneyness)`, `implied volatility  0.5500\nmoneyness           OTM\nconverged            True\nsurface              exact quotes + monthly interpolation`)}<p><code>cumulative_historical_vol</code> estimates realized annualized volatility from a caller-owned price history. Impossible option premiums fail rather than returning a misleading volatility.</p><h2 id="mark-to-market">Mark to market</h2>${codeBlock(`position = qv.MtMPosition(\n    commodity_id="TTF", delivery_period=period,\n    notional=5_000.0, trade_price=35.0, prior_mark_price=36.0,\n)\nmtm = qv.mark_to_market(\n    positions=[position], market_date=date(2026, 7, 16),\n    settlement_prices={("TTF", period): 36.85},\n    forward_curve=ttf_curve,\n)\nprint(mtm.positions[0])`, `current mark    36.85  settled\ndaily P&L       €4,250\ncumulative P&L  €9,250\nestimated count 0`)}<p>Settlement prices take precedence. A forward-curve fallback is explicitly marked <code>estimated</code>; when neither source covers the position, <code>NoPricingDataError</code> is raised.</p>`
  );

window.DOC_GUIDES.ppa = {title:"PPAs and interval settlement",description:"Construct every interval input, reconcile physical or financial settlement, and attribute typed hedges.",body:`
  <h2 id="contract">1. Define the delivery term and contract</h2>${codeBlock(`from datetime import UTC, datetime\nimport polars as pl\nimport quantvolt as qv\n\nstart = datetime(2026, 1, 1, 0, 0, tzinfo=UTC)\nend = datetime(2026, 1, 1, 2, 0, tzinfo=UTC)\ncontract = qv.PpaContract(\n    contract_id="plant-ppa",\n    bidding_zone="DE-LU",\n    fixed_price_per_mwh=70.0,\n    start_utc=start, end_utc=end,\n    volume_basis=qv.PpaVolumeBasis.BASELOAD,\n    settlement_type=qv.PpaSettlementType.PHYSICAL,\n    counterparty="Buyer GmbH",\n)`, `plant-ppa · DE-LU\nphysical · baseload\n2026-01-01 00:00Z → 02:00Z`)}
  <h2 id="settlement">2. Build and map caller-owned interval data</h2>${codeBlock(`intervals = pl.DataFrame({\n    "from": [\n        datetime(2026, 1, 1, 0, tzinfo=UTC),\n        datetime(2026, 1, 1, 1, tzinfo=UTC),\n    ],\n    "to": [\n        datetime(2026, 1, 1, 1, tzinfo=UTC),\n        datetime(2026, 1, 1, 2, tzinfo=UTC),\n    ],\n    "nomination_mwh": [10.0, 10.0],\n    "meter_mwh": [8.0, 12.0],\n    "day_ahead": [90.0, 80.0],\n    "short_buy": [100.0, 95.0],\n    "excess_sell": [40.0, 45.0],\n})\ncolumns = qv.PpaDataColumns(\n    interval_start_utc="from", interval_end_utc="to",\n    contracted_mwh="nomination_mwh",\n    metered_generation_mwh="meter_mwh",\n    spot_price_per_mwh="day_ahead",\n    shortfall_price_per_mwh="short_buy",\n    excess_price_per_mwh="excess_sell",\n)\nledger = qv.settle_ppa_frame(\n    contract, intervals, columns=columns\n)`, `row  contracted  metered  shortfall  excess\n1    10.0        8.0      2.0        0.0\n2    10.0       12.0      0.0        2.0\n\nEvery signed component reconciles to net_cashflow.`)}
  <h2 id="time-utc">Time is UTC in, local is the caller's job</h2><p>Every delivery interval is a half-open <code>[start_utc, end_utc)</code> pair on <code>PowerDeliveryInterval</code>, and both bounds must be timezone-aware and expressed in exactly UTC. The settlement engine never guesses a time zone, never resamples, and never repairs the clock. A naive datetime, or one carrying a non-zero offset such as CEST <code>+02:00</code>, is rejected at construction.</p>
  <div class="admonition warning"><b>Daylight saving is handled by requiring UTC input</b><p>Local wall-clock labels are not safe on a DST boundary: on the autumn fall-back the local hour repeats, and on the spring forward one local hour does not exist. QuantVolt settles on UTC intervals only, so a 23-hour spring day and a 25-hour autumn day simply produce fewer or more UTC intervals for the same civil day &mdash; the caller maps local delivery days to UTC, and the interval count follows automatically.</p></div>
  <p><code>settle_ppa_frame</code> additionally rejects duplicate interval starts, unsorted starts, and (with the default <code>require_contiguous=True</code>) any gap or overlap between one interval's end and the next interval's start. Resolution is whatever the caller's stamps encode: hourly, half-hourly and quarter-hourly all use the same type, and durations must be a whole number of minutes.</p>
  <p>QuantVolt supports three volume bases, selected by <code>PpaVolumeBasis</code>: <code>BASELOAD</code>, <code>SHAPED</code> and <code>PAY_AS_PRODUCED</code>. The engine does not shape volume itself &mdash; baseload and shaped differ only in the per-interval <code>contracted_mwh</code> the caller supplies. <code>PAY_AS_PRODUCED</code> enforces that <code>contracted_mwh</code> equals <code>metered_generation_mwh</code> on every interval. All settlement volumes are energy in <strong>MWh</strong> and all prices are <strong>EUR/MWh</strong>; <code>net_cashflow</code> and every signed ledger component are in EUR. The interval's <code>duration_hours</code> is available for MW-to-MWh conversion but is not applied by <code>settle_ppa_frame</code> to the MWh columns it already receives.</p>
  <h2 id="financial-ppa">3. Compare physical and financial CfD settlement</h2><table><thead><tr><th>Settlement</th><th>Producer cash-flow logic</th></tr></thead><tbody><tr><td>Physical</td><td>Contracted volume earns fixed price; shortfall is bought and excess is sold at explicit imbalance prices.</td></tr><tr><td>Financial CfD</td><td>Metered generation is sold spot; contracted volume receives fixed minus spot. There is no physical-delivery shortfall.</td></tr></tbody></table>${codeBlock(`interval = qv.PowerDeliveryInterval(\n    start_utc=intervals[0, "from"],\n    end_utc=intervals[0, "to"],\n)\none = qv.settle_ppa_interval(\n    contract, interval, contracted_mwh=10.0,\n    metered_generation_mwh=8.0, spot_price_per_mwh=90.0,\n    shortfall_price_per_mwh=100.0, excess_price_per_mwh=40.0,\n)`, `contract revenue  +€700\nshortfall purchase -€200\nnet before costs   +€500`)}
  <div class="admonition warning"><b>Imbalance prices are explicit</b><p>Batch physical settlement requires shortfall and excess columns by default. Spot-price substitution is available only with <code>MissingImbalancePricePolicy.USE_SPOT</code>. Typed hedges and a generic hedge-cashflow column are mutually exclusive.</p></div>
  <h2 id="hedges">4. Add a typed power hedge</h2>${codeBlock(`floor = qv.PowerHedgeContract(\n    hedge_id="revenue-floor",\n    hedge_type=qv.PowerHedgeType.FLOOR,\n    position=qv.PowerHedgePosition.LONG,\n    start_utc=start, end_utc=end,\n    volume_mwh=10.0, strike_per_mwh=60.0,\n    allocated_premium_per_mwh=2.0,\n)\nledger = qv.settle_ppa_frame(\n    contract, intervals, columns=columns, hedges=[floor]\n)\ndetail = qv.settle_power_hedges_frame(\n    [floor], intervals,\n    interval_start_column="from", interval_end_column="to",\n    spot_price_column="day_ahead",\n)`, `hedge ID       revenue-floor\nspot above floor payoff  €0\nallocated premium       -€20 per interval\ncontract-level detail reconciles to ledger hedge_cashflow`)}
  <h2 id="portfolio-settlement">5. Settle PPAs and hedges by position ID</h2>${codeBlock(`portfolio = qv.Portfolio((\n    qv.Position(contract, position_id="plant-ppa"),\n    qv.Position(floor, position_id="revenue-floor"),\n    qv.Position(power_future, position_id="exchange-hedge"),\n))\nrealized = qv.settle_energy_portfolio(\n    portfolio,\n    {"plant-ppa": intervals, "revenue-floor": intervals},\n)`, `settled\n├─ plant-ppa\n└─ revenue-floor\n\nunsettled\n└─ exchange-hedge  # uses its exchange settlement engine`)}
  <h2 id="nomination">6. Calibrate nominations without look-ahead</h2>${codeBlock(`nomination_columns = qv.PpaNominationColumns(\n    interval_start_utc="from", interval_end_utc="to",\n    metered_generation_mwh="meter_mwh",\n    shortfall_price_per_mwh="short_buy",\n    excess_price_per_mwh="excess_sell",\n)\nfit = qv.calibrate_ppa_nomination(\n    contract, calibration_data,\n    calibration_end_utc=cutoff,\n    capacity_mwh_per_interval=2.5,\n    columns=nomination_columns,\n    objective=qv.PpaNominationObjective.MAX_MEAN_MINUS_CFAR,\n    risk_aversion=1.0, confidence_level=0.95,\n)\nevaluation = qv.apply_ppa_nomination(\n    fit, evaluation_data,\n    interval_start_column="from", interval_end_column="to",\n)`, `selected volume and every candidate diagnostic\nmean cash flow · lower percentile · CFaR · objective\ncalibration cutoff and interval resolution enforced`)}
  <h2 id="validation-ppa">Validation checklist</h2><p>The batch boundary rejects empty data, missing columns, null/non-finite values, negative energy, duplicate or unsorted intervals, gaps when continuity is required, overlaps, rows outside the contract term, and duplicate hedge IDs. Nomination calibration and evaluation must additionally share one interval resolution (see <a href="#/guide/hedging" data-section="walk-forward">walk-forward nomination</a>).</p>
  <h2 id="dst-worked-example">7. A 25-hour daylight-saving day settles as 25 intervals</h2><p>On the autumn fall-back, <code>Europe/Berlin</code> <code>2026-10-25</code> is a 25-hour civil day. Mapping local midnight-to-midnight to UTC gives <code>2026-10-24 22:00Z &rarr; 2026-10-25 23:00Z</code>, which is 25 hourly UTC intervals. The caller supplies those UTC stamps; the settlement ledger has exactly one row per interval, so the extra hour is captured with no special-casing.</p>${codeBlock(`from datetime import UTC, datetime, timedelta\nfrom zoneinfo import ZoneInfo\nimport polars as pl\nimport quantvolt as qv\n\ntz = ZoneInfo("Europe/Berlin")\nstart_utc = datetime(2026, 10, 25, 0, tzinfo=tz).astimezone(UTC)\nend_utc = datetime(2026, 10, 26, 0, tzinfo=tz).astimezone(UTC)\n\nstarts, ends, t = [], [], start_utc\nwhile t < end_utc:\n    starts.append(t)\n    ends.append(t + timedelta(hours=1))\n    t += timedelta(hours=1)\n\ncontract = qv.PpaContract(\n    contract_id="wind", bidding_zone="DE-LU",\n    fixed_price_per_mwh=60.0,\n    start_utc=start_utc, end_utc=end_utc,\n    volume_basis=qv.PpaVolumeBasis.BASELOAD,\n)\nintervals = pl.DataFrame({\n    "interval_start_utc": starts, "interval_end_utc": ends,\n    "contracted_mwh": [10.0] * len(starts),\n    "metered_generation_mwh": [10.0] * len(starts),\n    "spot_price_per_mwh": [50.0] * len(starts),\n    "shortfall_price_per_mwh": [55.0] * len(starts),\n    "excess_price_per_mwh": [45.0] * len(starts),\n})\nledger = qv.settle_ppa_frame(contract, intervals)\nprint("UTC span:", start_utc, "->", end_utc)\nprint("interval count:", len(starts))\nprint("ledger rows:", ledger.height)\nprint("total net_cashflow:", float(ledger["net_cashflow"].sum()))`, `UTC span: 2026-10-24 22:00:00+00:00 -> 2026-10-25 23:00:00+00:00\ninterval count: 25\nledger rows: 25\ntotal net_cashflow: 15000.0`)}<p>The 15000.0 figure is 25 intervals &times; 10 MWh &times; 60 EUR/MWh: metered equals contracted, so there is no shortfall or excess leg and the fixed price applies to every one of the 25 hours. On the 23-hour spring day <code>2026-03-29</code> the identical code produces 23 rows; the interval count is driven entirely by the caller's UTC stamps.</p>
`};

window.DOC_GUIDES['portfolio-risk'].body += `
  <h2 id="delta-aggregation">7. Inspect factor ordering and delta aggregation</h2>${codeBlock(`matrix = qv.aggregate_delta(list(valuation.priced))\nprint(matrix.commodities)\nprint(matrix.periods)\nprint(matrix.values)`, `Rows      commodity IDs\nColumns   delivery periods\nValues    EUR P&L per one-unit price move\n\nScenario-matrix columns must follow this exact flattened order.`)}
  <h2 id="parametric-risk">8. Parametric delta and delta-gamma VaR</h2>${codeBlock(`import numpy as np\nfrom quantvolt.risk import parametric_var, delta_gamma_var\n\ndelta = np.array([4_950.0, 1_980.0])\ncov = np.array([[2.25, 0.72], [0.72, 4.00]])\nlinear = parametric_var(delta, cov, confidences=(0.95, 0.99))\nsecond_order = delta_gamma_var(\n    delta, gamma=np.array([[120.0, 0.0], [0.0, 40.0]]),\n    cov=cov, confidences=(0.95, 0.99),\n)`, `ParametricVaRResult\n  method         delta or delta_gamma\n  VaR values     ordered like confidences\n  P&L mean       includes gamma convexity\n  P&L variance   full moment calculation\n  P&L skewness   Cornish–Fisher input`)}
  <h2 id="covariance-risk">9. Forecast covariance</h2>${codeBlock(`from quantvolt.risk import ewma_covariance, garch11_covariance\n\n# rows are observations; columns are risk factors\newma = ewma_covariance(return_matrix, lam=0.94)\ngarch = garch11_covariance(return_matrix)\nassert ewma.shape == (return_matrix.shape[1],) * 2`, `EWMA covariance    explicit 0.94 decay\nGARCH(1,1) covariance fitted marginal variances + residual correlation`)}
  <h2 id="cfar-risk">10. Cash-Flow-at-Risk</h2>${codeBlock(`import numpy as np\nfrom quantvolt.risk import cash_flow_at_risk\n\nscenarios = [\n    {"power": 70.0, "generation": 8.0},\n    {"power": 90.0, "generation": 10.0},\n    {"power": 40.0, "generation": 5.0},\n]\ndef cashflow_model(scenario):\n    monthly = scenario["power"] * scenario["generation"]\n    return np.array([monthly, monthly * 0.95])\n\ncfar = cash_flow_at_risk(\n    cashflow_model, scenarios, horizon=2, seed=42,\n    consistency={"power": "same scenario as generation"},\n    confidence_level=0.95,\n)`, `CFaRResult\n  expected cash flow\n  lower percentile and CFaR shortfall\n  p50 and p95\n  all aggregate scenario cash flows\n  seed and consistency metadata`)}
  <h2 id="credit-risk">11. Counterparty Credit VaR</h2>${codeBlock(`from quantvolt.risk import credit_var\n\ncredit = credit_var(\n    positions=list(valuation.priced),\n    transition={"Utility BV": [0.99, 0.01]},\n    exposures={"Utility BV": 250_000.0},\n    recovery={"Utility BV": 0.40},\n    seed=42, path_count=100_000,\n    asset_correlation=0.20,\n    confidences=(0.95, 0.99),\n)`, `CreditVaRResult\n  expected credit loss\n  credit VaR 95 and 99\n  per-counterparty EAD, PD, recovery and expected loss\n  credit-risk-free positions reported separately`)}
`;

window.DOC_GUIDES.hedging = {title:"Hedging incomplete markets",description:"Compute identifiable hedge ratios, dynamic mean-variance strategies and leakage-safe PPA nominations.",body:`
  <h2 id="variance">Variance-minimizing hedge ratios</h2>${codeBlock(`import numpy as np\nfrom quantvolt.hedging import variance_min_hedge\n\n# Two traded hedges: TTF future and EUA future.\nsigma_hh = np.array([\n    [4.00, 0.30],\n    [0.30, 2.25],\n])\nsigma_ht = np.array([1.80, 0.45])\nratios = variance_min_hedge(sigma_hh, sigma_ht)\nprint(ratios)`, `[0.4394, 0.1414]\n\nRatios solve Σ_hh · h* = Σ_ht exactly.`)}<p>Singular or ill-conditioned hedge covariance is rejected. QuantVolt does not silently use a pseudo-inverse because collinear instruments make the ratios unidentified.</p><p><strong>The formula has no negative sign; the offset comes from the P&amp;L definition.</strong> Hedged P&amp;L is <code>Π = ΔV_total − Σ_t g_t·ΔH_t</code> &mdash; you subtract <code>g</code> units of the hedge instrument. So a positive <code>h*</code> means: against a long target exposure, sell (go short) <code>h*</code> units of the hedge instrument per unit of target; against a short target, buy. The ratio's sign tracks the target-hedge correlation; the subtraction in <code>Π</code> is what turns a positively correlated hedge into an offsetting trade.</p>
  <h2 id="cross">Single-instrument cross hedge</h2>${codeBlock(`from quantvolt.hedging import linear_cross_hedge\n\nratio = linear_cross_hedge(\n    rho=0.72, sigma_target=0.38, sigma_hedge=0.52\n)`, `hedge ratio  0.526154\nformula      ρ × σ_target / σ_hedge`)}
  <h2 id="decomposed-delta">Hybrid/decomposed delta</h2><p><code>decomposed_delta</code> applies the chain rule when a structured exposure depends on multiple modeled factors. The result separates the direct product delta from factor-loading contributions so residual hedge risk remains visible.</p>
  <h2 id="mean-variance">Local and global mean-variance strategies</h2><table><thead><tr><th>Function</th><th>Decision</th></tr></thead><tbody><tr><td><code>local_mean_variance</code></td><td>Optimizes each time step using its local increment covariance.</td></tr><tr><td><code>global_mean_variance</code></td><td>Solves the joint strategy over the full horizon and cross-time covariance.</td></tr></tbody></table><p>Both validate covariance dimensions, symmetry and conditioning before solving. Use the global strategy when cross-time dependency materially affects hedge allocation.</p>
  <h2 id="ppa-nomination">PPA nomination objectives</h2><table><thead><tr><th>Objective</th><th>Selection criterion</th></tr></thead><tbody><tr><td><code>MAX_MEAN_CASHFLOW</code></td><td>Highest average in-sample cash flow</td></tr><tr><td><code>MAX_MEAN_MINUS_CFAR</code></td><td>Mean minus risk-aversion × CFaR</td></tr></tbody></table><p>Every candidate still reports mean cash flow, lower percentile, CFaR and objective value regardless of which objective selects the winner.</p>
  <h2 id="walk-forward">Walk-forward nomination</h2>${codeBlock(`result = qv.walk_forward_ppa_nomination(\n    contract, history,\n    rebalance_utc=(cutoff_1, cutoff_2, cutoff_3),\n    evaluation_end_utc=contract.end_utc,\n    capacity_mwh_per_interval=2.5,\n    columns=nomination_columns,\n    objective=qv.PpaNominationObjective.MAX_MEAN_MINUS_CFAR,\n    risk_aversion=1.0, confidence_level=0.95,\n)`, `PpaWalkForwardResult\n  one fit per declared cutoff\n  evaluation rows strictly after each fit window\n  selected volume and realized cash flow by fold\n  aggregate out-of-sample performance`)}
`};

window.DOC_GUIDES.assets = {title:"Physical assets",description:"Optimize thermal dispatch and gas storage under explicit technical constraints.",body:`
  <h2 id="plant">Build a thermal-plant operating model</h2>${codeBlock(`from quantvolt.assets.plant import PlantModel, StartCost, StartState\n\nplant = PlantModel(\n    heat_rate=lambda output, temperature: 2.0 + 0.001 * output,\n    c_min=20.0,\n    c_max=lambda temperature: 100.0 if temperature <= 30.0 else 90.0,\n    variable_om_cost=3.5,\n    start_costs={\n        StartState.HOT: StartCost(500.0, 2.0, 0.2),\n        StartState.WARM: StartCost(1_000.0, 4.0, 0.4),\n        StartState.COLD: StartCost(2_000.0, 8.0, 0.8),\n    },\n    ramp_rate=40.0, d_min=2, d_shutdown=1, d_startup=1,\n    outage_rate=0.04, hot_max_downtime=2, warm_max_downtime=8,\n    representative_temperatures=(0.0, 20.0, 35.0),\n)`, `capacity     20–100 MW, temperature dependent\nramp rate    40 MW per period\nstarts       hot · warm · cold\nminimum run  2 periods`)}
  <h2 id="deterministic-asset">Perfect-foresight dispatch</h2>${codeBlock(`from quantvolt.assets import dispatch_deterministic\n\nschedule = dispatch_deterministic(\n    plant,\n    power_prices=[45, 50, 95, 110, 70, 35],\n    fuel_prices=[30, 30, 31, 31, 30, 29],\n    temperatures=[10, 10, 12, 14, 15, 14],\n    initial_online=False, initial_downtime=10,\n    output_step=20.0,\n)\nprint(schedule.output)\nprint(schedule.total_value)`, `One output/start/online decision per period\nTotal value includes generation margin, VOM and start costs\nAll ramp, min-run, min-down and startup-lag constraints enforced`)}<p>This dynamic program is a perfect-foresight upper bound, not a tradable valuation under uncertainty.</p>
  <h2 id="stochastic">Stochastic dispatch</h2><p><code>dispatch_value</code> accepts a <code>DispatchFactorModel</code> and prices operational flexibility with LSM or lattice methods. <code>PhysicalFactorMapping</code> transforms simulated factors into power, fuel and temperature paths. <code>DispatchDiagnostics</code> reports regression conditioning, exercise surfaces and boundary decisions; <code>MonteCarloEvaluation</code> reports path dispersion and standard error.</p>
  <h2 id="approximations-asset">Dispatch approximations</h2><p><code>bang_bang</code> and related approximation helpers are labeled approximations. <code>BangBangHedgeWarning</code> flags cases where a discontinuous on/off policy makes local hedges unreliable. Compare approximations against <code>dispatch_deterministic</code> or a stochastic benchmark before using them in risk.</p>
  <h2 id="asset-values">Three distinct asset values</h2><p>These are not interchangeable, and 1&rarr;3 do not increase monotonically in general. Always qualify a bare "asset value" as one of the three below, and name the function.</p><table><thead><tr><th>Value</th><th>Function(s)</th><th>What it is</th><th>Verified example</th></tr></thead><tbody>
    <tr><td>Physical operating margin</td><td><code>spark_spread</code> / <code>clean_spread</code></td><td>Per-MWh margin if the plant always ran: power &minus; heat_rate &times; fuel &minus; VOM &minus; carbon. Informational; can be negative; no discounting, no dispatch decision, no optionality.</td><td>clean spark spread Dec-26 = &minus;14.06 EUR/MWh</td></tr>
    <tr><td>Perfect-foresight optimisation value</td><td><code>storage_intrinsic</code>, <code>dispatch_deterministic</code></td><td>Optimal schedule chosen with full knowledge of the deterministic forward curve, subject to all physical constraints. A perfect-foresight upper bound under uncertainty; undiscounted DP; no re-optimisation to new information.</td><td>storage intrinsic = 1066.0</td></tr>
    <tr><td>Stochastic / risk-adjusted economic value</td><td><code>storage_value</code>, <code>dispatch_value</code></td><td>Expected value of the optimal policy that re-optimises as prices evolve. Includes extrinsic optionality; carries a Monte Carlo standard error.</td><td>storage total = 1066.15 = intrinsic 1066.0 + extrinsic 0.1515 (SE 0.2994)</td></tr>
  </tbody></table>
  <h2 id="storage">Gas-storage intrinsic value</h2>${codeBlock(`from quantvolt.assets import StorageModel, storage_intrinsic\n\nstore = StorageModel(\n    min_inventory=0.0, max_inventory=100.0,\n    initial_inventory=50.0, terminal_inventory=50.0,\n    injection_rate=lambda inventory: 20.0,\n    withdrawal_rate=lambda inventory: 25.0,\n    injection_cost=0.20, withdrawal_cost=0.15,\n    injection_loss=0.01, withdrawal_loss=0.01,\n    carry_cost=0.02, terminal_penalty=None,\n)\nintrinsic = storage_intrinsic(\n    store, ttf_curve, inventory_step=10.0\n)`, `IntrinsicResult\n  optimal injection/withdrawal action per period\n  complete inventory trajectory\n  per-period cash flow\n  total forward-locked intrinsic value`)}
  <h2 id="extrinsic-storage">Storage extrinsic value</h2><p><code>storage_value</code> combines a <code>StorageFactorModel</code>, simulated spot paths and LSM continuation values into a stochastic value with a standard error &mdash; see the <a href="#/guide/tutorial-storage">storage tutorial</a> for when that standard error makes the extrinsic estimate indistinguishable from zero.</p>
  <h2 id="governance">Long-dated valuation governance</h2><table><thead><tr><th>Tool</th><th>Question answered</th></tr></thead><tbody><tr><td><code>valuation_benchmark</code></td><td>How far is an approximation from a declared benchmark?</td></tr><tr><td><code>var_applicability_guard</code></td><td>Is the proposed VaR method defensible for this asset and horizon?</td></tr><tr><td><code>furthest_forward_lower_bound</code></td><td>What defensible lower bound follows from the liquid horizon?</td></tr><tr><td><code>CorporatePremium</code></td><td>Which non-market risk premium is being applied and why?</td></tr></tbody></table>
`};

window.DOC_GUIDES['curve-models'] = {title:"Stochastic forward-curve models",description:"Model factor-driven evolution after the initial market curve has been constructed.",body:`
  <h2 id="schwartz-smith">Two-factor Schwartz–Smith model</h2>${codeBlock(`import numpy as np\nfrom quantvolt.curvemodels import (\n    SchwartzSmithParams, forward_curve, log_forward_curve,\n)\n\nparams = SchwartzSmithParams(\n    kappa=1.8, sigma_chi=0.45, sigma_xi=0.20,\n    mu_xi=0.03, rho=0.25,\n    lambda_chi=0.05, lambda_xi=0.01,\n)\ntenors = np.array([0.25, 0.50, 1.0, 2.0])\nforwards = forward_curve(\n    params, chi=0.08, xi=3.50, t=0.0, tenors=tenors\n)`, `Short-factor loading decays as exp(−κτ)\nLong-dated forwards depend primarily on ξ and A(τ)\nmu_xi_star = mu_xi − lambda_xi`)}
  <h2 id="ss-simulation">Exact factor simulation and calibration</h2>${codeBlock(`from quantvolt.curvemodels import simulate\n\nfactors = simulate(\n    params, chi0=0.08, xi0=3.50,\n    dt=1/12, steps=24, path_count=10_000, seed=42,\n)\nprint(factors.shape)`, `(10000, 25, 2)\naxes: path · time (including initial) · [chi, xi]`)}<p><code>calibrate</code> fits parameters to a time series of observed log-forward curves using a Kalman filter and reports <code>CalibrationDiagnostics</code>, standard errors and optimization status.</p>
  <h2 id="multifactor">Multifactor/multi-commodity model</h2>${codeBlock(`from quantvolt.curvemodels import MultifactorForwardModel\n\n# 12 monthly time buckets, 2 factors, 3 flattened tenors.\nloadings = np.zeros((12, 2, 3))\nloadings[:, 0, :] = [0.55, 0.45, 0.35]\nloadings[:, 1, :] = [0.10, 0.18, 0.25]\nmodel = MultifactorForwardModel(loadings, dt=1/12)`, `n_steps   12\nn_factors 2\nn_tenors  3\nloadings copied and made read-only`)}
  <h2 id="induced">Induced covariance and option variance</h2>${codeBlock(`from quantvolt.curvemodels import (\n    induced_correlation, induced_covariance, option_variance,\n)\n\ncov = induced_covariance(model, step=0)\ncorr = induced_correlation(model, step=0)\nvariance = option_variance(model, tenor=0, expiry_step=6)`, `covariance  Gram matrix of factor loadings\ncorrelation unit diagonal for active tenors\noption variance cumulative loading variance to expiry`)}
  <h2 id="model-simulation">Risk-neutral forward simulation</h2>${codeBlock(`from quantvolt.curvemodels import simulate_forwards\n\npaths = simulate_forwards(\n    model, initial_forwards=[36.85, 35.93, 35.02],\n    steps=12, path_count=10_000, seed=42,\n    commodity_ids=["TTF", "TTF", "TTF"],\n)\nprint(paths.shape)`, `(10000, 13, 3)\nrisk-neutral drift = −½ diag(covariance)\ninitial curve matched exactly on every path`)}
  <h2 id="power-warning">Lognormal power warning</h2><p><code>warn_if_power_like</code> emits <code>LognormalPowerWarning</code> for EPEX/Phelix/power-like IDs. A lognormal model cannot represent negative prices, spikes or heavy tails, so its use for power requires an explicit modeling justification.</p>
`};

window.DOC_GUIDES.statistics = {title:"Energy time-series statistics",description:"Inspect distribution, stationarity, dependency and mean reversion before selecting a model.",body:`
  <h2 id="statistics-setup">Reproducible sample</h2>${codeBlock(`from datetime import date, timedelta\n\nimport numpy as np\nimport polars as pl\n\nrng = np.random.default_rng(42)\ninnovations = rng.normal(0.0, 0.65, 300)\nvalues = np.empty(300)\nvalues[0] = 34.0\nfor i in range(1, len(values)):\n    values[i] = 34.0 + 0.92 * (values[i - 1] - 34.0) + innovations[i]\nprices = pl.Series("TTF", values)\ndates = [date(2025, 1, 1) + timedelta(days=i) for i in range(len(values))]`, `300 deterministic observations from a seeded mean-reverting process`)}
  <h2 id="descriptive">Descriptive statistics and moments</h2>${codeBlock(`from quantvolt.stats import descriptive_stats, moments\n\nsummary = descriptive_stats(prices)\ncentral = moments(prices, order=4)\nprint(summary.n, summary.mean, summary.std)\nprint(summary.skewness, summary.kurtosis, summary.t_statistic)\nprint(central)`, `DescriptiveStats\n  n · mean · sample standard deviation\n  skewness · excess kurtosis · mean-vs-zero t statistic\nCentral moments m1 through m4`)}<p>Nulls are dropped without mutating the series. Non-finite values and insufficient samples fail explicitly.</p>
  <h2 id="normality">Normality tests</h2>${codeBlock(`from quantvolt.stats import NormalityTestType, test_normality\n\nfor method in NormalityTestType:\n    result = test_normality(\n        prices, test_type=method, acceptance_level=0.05\n    )\n    print(method.value, result.statistic, result.p_value, result.is_normal)`, `jarque_bera · shapiro_wilk · dagostino · anderson\nEach result: statistic, p-value (NaN for Anderson), acceptance decision`)}<p>Each procedure enforces its own minimum sample size. A p-value is evidence under the selected null test—not proof that an energy-price series is Gaussian.</p>
  <h2 id="stationarity">ADF, KPSS and Samuelson diagnostics</h2>${codeBlock(`from quantvolt.stats import test_stationarity\n\nresult = test_stationarity(\n    prices, contract_expiry=date(2026, 12, 31),\n    observation_dates=dates, min_observations=30,\n)\nprint(result.adf_p_value, result.kpss_p_value)\nprint(result.is_stationary, result.samuelson_effect_detected)`, `StationarityResult\n  ADF statistic and p-value\n  KPSS statistic and p-value\n  combined stationarity interpretation\n  Samuelson-effect diagnostic`)}<p>ADF and KPSS have opposite null hypotheses. The combined result preserves both rather than hiding a disagreement.</p>
  <div class="admonition warning"><b>Read the test, not just the verdict</b><ul>
    <li><strong>Two tests must agree.</strong> <code>test_stationarity</code> reports <code>is_stationary</code> only when ADF rejects the unit-root null <em>and</em> KPSS fails to reject stationarity &mdash; read <code>adf_p_value</code> and <code>kpss_p_value</code>, not just the boolean.</li>
    <li><strong>Multiple testing.</strong> Four normality tests exist (Jarque-Bera, Shapiro-Wilk, D'Agostino-Pearson, Anderson-Darling), each tuned to a different regime. Running all four and keeping the one that "passes" inflates false-accept rate; pick the test for your sample size before looking at p-values.</li>
    <li><strong>Small-sample power.</strong> Each test enforces a minimum <code>n</code> (Shapiro &ge; 3, D'Agostino/Anderson &ge; 8; <code>test_stationarity</code> needs &ge; 30) and raises <code>InsufficientDataError</code> below it. Above the floor but still small, failure to reject is weak power, not evidence for the null.</li>
    <li><strong>Structural breaks.</strong> ADF/KPSS assume one regime. Bidding-zone splits, generation-stack shifts and comparable market events break that assumption; test sub-windows rather than one verdict spanning a break.</li>
    <li><strong>Rolling-window instability.</strong> <code>rolling_correlation</code> output moves with the window; a hedge ratio or correlation is a window artefact, not a constant.</li>
    <li><strong>Autocorrelation and heteroskedasticity.</strong> Energy returns are serially dependent and their variance clusters. <code>fit_ou</code> assumes constant OU parameters; check residuals before trusting a normality p-value or a VaR built on them.</li>
  </ul></div>
  <h2 id="correlation-stats">Correlation</h2>${codeBlock(`from quantvolt.stats import correlation_matrix, rolling_correlation\n\nttf_prices = prices\npower_prices = pl.Series("POWER", 45.0 + 1.4 * values + rng.normal(0, 2, 300))\neua_prices = pl.Series("EUA", 80.0 + rng.normal(0, 1.5, 300))\nframe = pl.DataFrame({"TTF": ttf_prices, "POWER": power_prices, "EUA": eua_prices})\npearson = correlation_matrix(frame, method="pearson")\nspearman = correlation_matrix(frame, method="spearman")\nrolling = rolling_correlation(frame["TTF"], frame["POWER"], window=30)`, `Pairwise Pearson and Spearman matrices\nRolling series has window − 1 leading null values`)}
  <h2 id="mean-reversion">Ornstein–Uhlenbeck fit</h2>${codeBlock(`from quantvolt.stats import fit_ou\n\nfit = fit_ou(prices, dt=1/252)\nprint(fit.reversion_speed, fit.long_run_mean)\nprint(fit.volatility, fit.half_life)`, `MeanReversionParams\n  reversion_speed κ\n  long_run_mean μ\n  diffusion volatility σ\n  half_life = ln(2) / κ`)}<p>The exact AR(1) mapping requires a fitted slope strictly between zero and one. Non-mean-reverting or explosive samples raise instead of producing meaningless continuous-time parameters.</p>
`};

window.DOC_GUIDES['market-utils'] = {title:"Market utilities",description:"Compute transport, weather and outage features from caller-owned observations.",body:`
  <h2 id="transmission-utils">Transmission cost</h2>${codeBlock(`from quantvolt.market import Pipeline, transmission_cost\n\npipeline = Pipeline(distance=120.0, tariff=0.42)\ncost = transmission_cost(pipeline, volume=10_000.0)`, `distance 120 km (informational)\nvolume   10,000 MWh\ntariff   €0.42/MWh\ncost     €4,200`)}
  <h2 id="weather-utils">Temperature and degree days</h2>${codeBlock(`from datetime import date\n\nimport polars as pl\nfrom quantvolt.market import degree_days\n\ntemperatures = pl.DataFrame({\n    "location": ["Amsterdam", "Amsterdam", "Amsterdam"],\n    "date": [date(2026, 1, 1), date(2026, 1, 2), date(2026, 1, 3)],\n    "temp_celsius": [4.0, 7.5, 20.0],\n})\nfeatures = degree_days(temperatures, base_celsius=18.0)`, `date        heating DD  cooling DD\n2026-01-01  14.0        0.0\n2026-01-02  10.5        0.0\n2026-01-03   0.0        2.0`)}
  <h2 id="outage-records">Outage records and lifecycle</h2><p><code>OutageRecord</code> carries type, status, interval and unavailable capacity. <code>OutageDataset</code> validates records as one immutable analysis set. Planned, unplanned, forced, maintenance, service and partial derating categories remain distinct; cancelled records never contribute to realized KPIs.</p>
  <h2 id="reliability-kpis">Reliability KPIs</h2><table><thead><tr><th>Function</th><th>Definition</th></tr></thead><tbody><tr><td><code>availability_factor</code></td><td>Available hours / observation hours</td></tr><tr><td><code>equivalent_availability_factor</code></td><td>Capacity-weighted availability including deratings</td></tr><tr><td><code>forced_outage_rate</code></td><td>Forced hours / (forced + service hours)</td></tr><tr><td><code>efor</code></td><td>Capacity-equivalent forced outage rate</td></tr><tr><td><code>mttr</code></td><td>Forced outage hours / forced event count</td></tr><tr><td><code>mtbf</code></td><td>Observation hours / forced event count</td></tr><tr><td><code>outage_frequency</code></td><td>Annualized forced event frequency</td></tr><tr><td><code>unavailable_energy</code></td><td>Σ unavailable MW × duration hours</td></tr></tbody></table>
`};

window.DOC_GUIDES['workflow-guide'] = {title:"Experimental: model-selection workflow",description:"A contributor extension pattern for a seven-step audit trail. Placeholder pricing output — not a finished pricing workflow.",body:`
  <div class="admonition warning"><b>Experimental: contributor extension pattern</b><p><code>ModelingWorkflow</code> is a fixed seven-step audit-trail skeleton, not a finished pricing workflow: its default steps carry no market data and the example below prints a placeholder <code>0.0</code> result. It exists so a contributor can inject real fitting/pricing callables (via <code>WorkflowSteps</code>) for a specific structured product while keeping the audit trail, the step order and the acceptance-criteria checks fixed. Do not copy the example as-is expecting a real price.</p></div>
  <h2 id="workflow-product">Define the structured product</h2><p><code>StructuredProduct</code> records the payoffs, market factors, operational factors and horizon that a candidate model must represent. <code>QualitativeAnalysis</code> identifies optionality, path dependence, constraints and incomplete-market risks before fitting.</p>
  <h2 id="workflow-criteria">Set selection criteria</h2>${codeBlock(`from quantvolt.workflow import ModelSelectionCriteria\n\ncriteria = ModelSelectionCriteria(\n    min_observations=252,\n    max_missing_pct=0.05,\n    min_r_squared=0.70,\n    max_rmse_pct=0.10,\n    max_parameter_drift=0.20,\n    require_risk_factor_separation=True,\n)`, `Acceptance thresholds are explicit and retained in the audit trail.`)}
  <h2 id="workflow-steps">Run the seven declared steps</h2>${codeBlock(`from quantvolt.workflow import ModelingWorkflow, StructuredProduct\n\nproduct = StructuredProduct(\n    name="TTF indexed supply",\n    payoff_description="monthly indexed gas delivery",\n    risk_factors=("price:gas",),\n)\nresult = ModelingWorkflow().run(product, criteria)\nprint(result.steps_executed)\nprint(result.hedges)\nprint(result.price)`, `(1, 2, 3, 4, 5, 6, 7)\nStaticHedge(instrument_kind='gas_forward', risk_factor='price:gas', hedge_ratio=1.0)\n0.0   # placeholder: default skeleton has no market data`)}<ol><li>Qualitative product analysis</li><li>Static hedge construction</li><li>Residual analysis</li><li>Residual-model selection</li><li>Data sufficiency assessment</li><li>Consistency checks</li><li>Final price and hedge recommendation</li></ol><p><code>DEFAULT_STEPS</code> supplies the standard order. <code>WorkflowSteps</code> allows explicit caller composition without hiding which steps ran. <strong>The <code>0.0</code> above is a placeholder, not a computed price</strong> &mdash; the default step 7 returns zero residual value because the skeleton has no market data; inject a production pricing callable via <code>WorkflowSteps</code> for a real structured product.</p>
  <h2 id="workflow-result">Retain the result and audit evidence</h2><p><code>WorkflowResult</code> carries the selected approach together with <code>DataSufficiencyReport</code>, <code>StaticHedge</code>, <code>ResidualAnalysis</code>, <code>ResidualModel</code> and <code>ConsistencyReport</code>. A recommendation therefore remains traceable to data and validation evidence.</p>
`};

window.DOC_GUIDES.data = {title:"Data and optional datasets",description:"Discover, download, verify, and cache immutable research datasets without inflating the QuantVolt package.",body:`
  <h2 id="dataset-catalog">Optional versioned datasets</h2><p>Large research snapshots are GitHub Release assets—not package files and not automatic downloads. The packaged catalog records a stable ID, immutable version, format, byte size, SHA-256, license, provenance and direct release URL for every dataset.</p>${codeBlock(`from quantvolt.data import datasets\n\nfor record in datasets.list_datasets():\n    print(record.dataset_id, record.version, record.size)\n\nrecord = datasets.info("smard-de-power-experiment")\nprint(record.license, record.source)`, `9 optional datasets\nNo network call occurs during list() or info().`)}
  <h2 id="dataset-fetch">Fetch one dataset explicitly</h2>${codeBlock(`from quantvolt.data import datasets\n\nfile_path = datasets.fetch("smard-de-power-experiment")\nassert datasets.verify("smard-de-power-experiment")\nprint(file_path)`, `~/.cache/quantvolt/datasets/2026.07/\n  smard_de_power_experiment_intervals.parquet\n\nDownloaded through a temporary file, then size/hash verified and atomically installed.`)}<p>The equivalent CLI is <code>quantvolt data fetch smard-de-power-experiment</code>. Existing verified files are reused; <code>--force</code> performs a fresh download.</p>
  <h2 id="dataset-cache">Cache, offline mode and reproducibility</h2>${codeBlock(`QUANTVOLT_DATA_DIR=/srv/quantvolt-data quantvolt data fetch jrc-enagad-daily-demand\nquantvolt data verify jrc-enagad-daily-demand\nquantvolt data path jrc-enagad-daily-demand`, `/srv/quantvolt-data/2026.05/jrc_enagad_daily_demand.parquet`)}<p>Set <code>QUANTVOLT_DATA_DIR</code> for a shared or project-specific cache. In Python, <code>fetch(id, offline=True)</code> refuses network access and succeeds only when the exact version is already present and verified. No dataset is fetched during <code>import quantvolt</code>.</p>
  <div class="admonition note"><b>Optional imperative shell</b><p>Install <code>quantvolt[data]</code> for HTTP adapters. The analytics core never imports them and every workflow accepts caller-owned Polars data.</p></div>
  <h2 id="providers">Provider status</h2><table><thead><tr><th>Provider (class)</th><th>Status</th><th>Authentication</th><th>License note</th><th>Returned schema</th></tr></thead><tbody>
    <tr><td><code>EntsoeSource</code></td><td>Implemented</td><td>Free personal token (<code>Credentials(token=...)</code> or <code>QUANTVOLT_ENTSOE_TOKEN</code>)</td><td>ENTSO-E Transparency Platform terms; free registration</td><td><code>[time_series_index, period_index, position, interval_start_utc, interval_end_utc, duration_hours, value]</code></td></tr>
    <tr><td><code>EntsogSource</code></td><td>Implemented</td><td>Keyless</td><td>ENTSOG Transparency Platform terms</td><td><code>[point, direction, date, value, unit]</code></td></tr>
    <tr><td><code>OpenMeteoSource</code></td><td>Implemented</td><td>Keyless</td><td>Open-Meteo terms (weather, not a market)</td><td><code>[location, date, temp_celsius]</code></td></tr>
    <tr><td><code>SmardSource</code></td><td>Implemented</td><td>Keyless</td><td>Bundesnetzagentur SMARD terms; DE-LU only</td><td><code>[interval_start_utc, interval_end_utc, local_start, local_date, utc_offset_minutes, duration_minutes, bidding_zone, price_eur_per_mwh, source]</code></td></tr>
    <tr><td><code>NetztransparenzSource</code></td><td>Implemented</td><td>OAuth2 client-credentials</td><td>Official German reBAP; DE-LU imbalance</td><td><code>[interval_start_utc, interval_end_utc, shortfall_price_per_mwh, excess_price_per_mwh]</code></td></tr>
    <tr><td><code>EexSource</code></td><td><strong>Stub</strong> (raises)</td><td>Paid API key</td><td>EEX Group subscription required</td><td>n/a</td></tr>
    <tr><td><code>IceSource</code></td><td><strong>Stub</strong></td><td>Paid API key</td><td>ICE Endex data licence required</td><td>n/a</td></tr>
    <tr><td><code>EpexSource</code></td><td><strong>Stub</strong></td><td>Paid API key</td><td>EPEX SPOT data agreement required</td><td>n/a</td></tr>
    <tr><td><code>NordPoolSource</code></td><td><strong>Stub</strong></td><td>Paid API key</td><td>Nord Pool data licence required</td><td>n/a</td></tr>
    <tr><td><code>LsegSource</code></td><td><strong>Stub</strong></td><td>Paid API key</td><td>LSEG/Refinitiv subscription required</td><td>n/a</td></tr>
  </tbody></table><p>Adapters ship no credentials: they are read only from an explicit <code>Credentials</code> object or a documented <code>QUANTVOLT_&lt;PROVIDER&gt;_TOKEN</code> env var, never persisted, cached or logged. All 5 commercial classes raise <code>DataSourceError</code> naming the credential to configure until a paid licence is wired. The package imposes no caching or persistence and never writes fetched data to disk.</p>
  <h2 id="credentials-data">Credentials and errors</h2><p><code>Credentials</code> and <code>OAuthClientCredentials</code> keep authentication explicit. Provider failures map to <code>AuthenticationError</code>, <code>RateLimitError</code> or <code>DataUnavailableError</code>, all under <code>DataSourceError</code>. Documentation never embeds secrets.</p>
  <h2 id="fetch">Fetch and map reBAP</h2>${codeBlock(`from quantvolt.data import NetztransparenzSource, attach_rebap_prices\n\nsource = NetztransparenzSource()  # reads documented environment variables\nrebap = source.rebap(start_utc, end_utc)\nsettlement_data = attach_rebap_prices(\n    caller_data, rebap,\n    interval_start_column="from",\n    interval_end_column="to",\n)`, `Join keys  interval start + interval end\nMissing matches rejected\nDuplicate matches rejected\nExisting imbalance columns never overwritten`)}
  <h2 id="smard-data">SMARD resolution</h2><p><code>SmardResolution</code> makes the requested German data frequency explicit. Returned frames preserve timestamps, units and provider fields required for auditing.</p>
  <h2 id="snapshots">Snapshot and offline replay</h2>${codeBlock(`from quantvolt.data import restore, snapshot\n\npayload = snapshot(curve)\nreplayed = restore(payload)\nassert replayed == curve`, `Provider call is not needed for replay.\nThe restored model equals the original snapshot.`)}<p>For production, save validated provider output in caller-owned storage, record the retrieval parameters, and run analytics against that frozen snapshot.</p>
`};

window.DOC_GUIDES['end-to-end'] = {title:"End-to-end energy workflows",description:"Follow complete analysis paths across market data, models, valuation, risk, settlement, and governance.",body:""};  // body assigned below (single authoritative definition)

window.DOC_GUIDES['rust-monte-carlo'] = {title:"Rust & Monte Carlo",description:"Run QuantVolt’s native seeded simulation kernels and build full-revaluation energy risk workflows.",body:`
  <h2 id="native-architecture">Native architecture</h2><div class="dependency-flow"><code>Python API</code><span>validation →</span><code>quantvolt._core</code><span>PyO3 →</span><code>Rust kernels</code><span>→</span><code>NumPy arrays</code></div><p>QuantVolt keeps domain objects, shape checks, covariance validation and public exceptions in Python. CPU-intensive path generation runs in the bundled Rust crate through PyO3. The extension exports four kernels: Asian-option Monte Carlo, Ornstein–Uhlenbeck paths, constant-dynamics correlated forwards, and time-varying correlated forward term structures.</p><table><thead><tr><th>Python entry point</th><th>Rust kernel</th><th>Result shape</th></tr></thead><tbody><tr><td><code>asian_monte_carlo</code></td><td><code>asian_mc::asian_monte_carlo</code></td><td>premium, standard error</td></tr><tr><td><code>simulate_ou_paths</code></td><td><code>paths::simulate_ou</code></td><td><code>(paths, steps + 1)</code></td></tr><tr><td><code>simulate_correlated_forwards</code></td><td><code>paths::simulate_correlated_forwards</code></td><td><code>(paths, steps + 1, factors)</code></td></tr><tr><td><code>simulate_correlated_term_structure</code></td><td><code>paths::simulate_correlated_forwards_term</code></td><td><code>(paths, steps + 1, factors)</code></td></tr></tbody></table>
  <h2 id="native-build">Build and install</h2><div class="admonition note"><b>Wheel users</b><p>A platform wheel contains <code>quantvolt._core</code>; no Rust toolchain is required. Contributors building from source need Rust and Maturin.</p></div>${codeBlock(`uv sync\nmaturin develop\n\n# Verify that the compiled module is importable.\nuv run python -c "from quantvolt import _core; print(_core.__name__)"\n\n# Test both sides of the boundary.\ncargo test\nuv run pytest tests/property/test_simulation_properties.py`, `quantvolt._core\nRust unit tests + Python boundary/property tests`)}<p>The crate is configured by <code>Cargo.toml</code>, lives under <code>rust/</code>, and is built through the Maturin backend declared in <code>pyproject.toml</code>.</p>
  <h2 id="asian-native">Seeded Asian-option Monte Carlo</h2>${codeBlock(`from quantvolt.numerics import asian_monte_carlo\n\npremium, standard_error = asian_monte_carlo(\n    forward=36.85, strike=38.0, sigma=0.55,\n    time_to_expiry=0.4, discount_factor=0.99,\n    averaging_points=12, option_type="call",\n    geometric=False, seed=7, path_count=50_000,\n    antithetic=True,\n)\nprint(premium, standard_error)`, `premium         2.623289\nstandard error  0.021925\nseed            7\npaths           50,000`)}<p>The result reports sampling uncertainty explicitly. With the same inputs, seed, path count, QuantVolt version, architecture and native build, the Rust RNG produces identical results. Its random stream is intentionally not required to match NumPy.</p>
  <h2 id="ou-native">Mean-reverting OU paths</h2>${codeBlock(`from quantvolt.numerics import simulate_ou_paths\n\npaths = simulate_ou_paths(\n    x0=34.0, kappa=2.5, mu=32.0, sigma=0.65,\n    dt=1/12, steps=24, path_count=10_000, seed=42,\n)\nprint(paths.shape)\nprint(paths[:, 0].min(), paths[:, 0].max())`, `(10000, 25)\n34.0 34.0`)}<p>The recursion is <code>x[t+1] = x[t] + κ(μ − x[t])dt + σ√dt·z</code>. Use <code>fit_ou</code> in <code>quantvolt.stats</code> to estimate parameters and this function for forward simulation.</p>
  <h2 id="correlated-native">Correlated multi-commodity forwards</h2>${codeBlock(`import numpy as np\nfrom quantvolt.numerics import build_covariance, simulate_correlated_forwards\n\nforwards = np.array([36.85, 92.0, 78.0])\nvolatility = np.array([0.55, 0.38, 0.24])\ncorrelation = np.array([\n    [1.00, 0.61, 0.28],\n    [0.61, 1.00, 0.35],\n    [0.28, 0.35, 1.00],\n])\ncovariance = build_covariance(volatility, correlation, dt=1/12)\ndrift_q = -0.5 * np.diag(covariance)\npaths = simulate_correlated_forwards(\n    z0=np.log(forwards), drift=drift_q, cov=covariance,\n    steps=12, path_count=20_000, seed=42, antithetic=True,\n)\nlevels = np.exp(paths)\nprint(levels.shape)`, `(20000, 13, 3)\naxes: path · time including initial state · flattened factor`)}<p>The simulator is measure-agnostic: supply physical drift for risk/scenarios or <code>−½ diag(C)</code> for risk-neutral lognormal forward simulation. Zero-variance coordinates are expired/frozen and remain unchanged.</p>
  <h2 id="term-native">Time-varying term-structure simulation</h2>${codeBlock(`from quantvolt.numerics import (\n    CorrelatedSimulationRequest, simulate_correlated_term_structure,\n)\n\nrequest = CorrelatedSimulationRequest(\n    z0=np.log([36.85, 35.90]),\n    drift_steps=np.zeros((3, 2)),\n    covariance_steps=np.repeat(\n        np.array([[[0.010, 0.003], [0.003, 0.006]]]), 3, axis=0\n    ),\n    active_steps=np.array([\n        [True, True], [True, True], [False, True],\n    ]),\n    path_count=10_000, seed=42, antithetic=True,\n)\npaths = simulate_correlated_term_structure(request)\nprint(paths.shape)`, `(10000, 4, 2)\nfirst tenor freezes after step 2; second remains active`)}<p>Each step has its own drift, covariance and live-tenor mask. Arrays are copied at the public boundary, validated per step, converted to contiguous <code>float64</code>, and only then passed to Rust.</p>
  <h2 id="mc-var-native">Full-revaluation Monte Carlo VaR</h2>${codeBlock(`import numpy as np\nfrom quantvolt.numerics import DriftKind\nfrom quantvolt.risk import FactorModel, TaggedDrift, monte_carlo_var\n\nfactors = (("TTF", dec_26), ("EEX_PHELIX_DE", dec_26))\nmodel = FactorModel(\n    market_data=market_data, factors=factors,\n    sigma=np.array([0.55, 0.38]),\n    corr=np.array([[1.0, 0.61], [0.61, 1.0]]),\n)\ndrift = TaggedDrift(\n    values=np.array([0.02, 0.01]), kind=DriftKind.PHYSICAL,\n)\nresult = monte_carlo_var(\n    positions, model, drift, holding_period=10/252,\n    path_count=20_000, seed=42, antithetic=True,\n)`, `McVaRResult\n  VaR 95 and 99 + bootstrap standard errors\n  CVaR 97.5 + bootstrap standard error\n  path count · holding period · seed`)}<p>Every terminal path rebuilds the affected forward curves and fully reprices the portfolio. Risk-neutral drift is rejected because VaR requires a physical distribution. Bootstrap resampling preserves whole antithetic pairs.</p>
  <h2 id="mc-validation">Validation and native errors</h2><table><thead><tr><th>Condition</th><th>Public failure</th></tr></thead><tbody><tr><td>Native module not built</td><td><code>NativeExtensionError</code> with <code>maturin develop</code> guidance</td></tr><tr><td>Wrong dimensions, non-finite data, invalid counts</td><td><code>ValidationError</code> before Rust executes</td></tr><tr><td>Non-symmetric or non-PSD covariance</td><td><code>ValidationError</code>; <code>repair=True</code> opts into projection</td></tr><tr><td>Native Cholesky/numerical failure</td><td><code>NumericalError</code> translated at the Python boundary</td></tr><tr><td>Monte Carlo VaR below minimum paths</td><td><code>ValidationError</code> before simulation</td></tr></tbody></table><div class="admonition warning"><b>PSD repair is explicit</b><p>QuantVolt never silently changes covariance. <code>repair=True</code> symmetrizes and clips negative eigenvalues to the nearest positive-semidefinite covariance.</p></div>
  <h2 id="mc-performance">Performance and convergence</h2><ul><li>Pass contiguous <code>float64</code> arrays; the boundary normalizes other array-like inputs.</li><li>Use explicit seeds in tests, reports and production replays.</li><li>Record path count and standard error with every estimate.</li><li>Antithetic variates reduce variance by pairing <code>+ε</code> and <code>−ε</code>.</li><li>Increase paths until the reported standard error is acceptable for the decision—not until a rounded price merely looks stable.</li><li>Use constant dynamics when valid; use <code>CorrelatedSimulationRequest</code> when covariance or tenor activity changes by step.</li></ul><p>The checked executable is <code>site/examples/verify_native_monte_carlo.py</code>. Rust property tests additionally verify covariance recovery and seed determinism (same inputs, seed, QuantVolt version, architecture and native build) at larger path counts.</p>
`};

// Standalone tutorials: every code block below and its printed output is copied verbatim
// from an actual run of the paired site/examples/verify_tutorial_*.py script.
window.DOC_GUIDES['tutorial-spark'] = {title:"Tutorial: spark spread to hedge",description:"Power, gas and EUA curves to a clean spark spread option, a native tolling position in a portfolio, and a variance-minimizing hedge.",body:`
  <p>Full runnable script: <code>site/examples/verify_tutorial_spark.py</code>. Crosses <code>pricing.spreads</code> (informational margin), the native <code>SpreadOptionContract</code> / <code>TollingAgreement</code> portfolio instruments, and <code>quantvolt.hedging</code>.</p>
  <h2 id="setup">1. Physical clean spark spread</h2><p>The plant's per-MWh margin if it always ran, using the shared TTF/power/EUA curves from <code>shared_setup.example_market()</code>.</p>${codeBlock(`spark = qv.spark_spread(\n    market.power_curve, market.ttf_curve,\n    heat_rate=2.0, variable_cost=3.5, emissions_cost=0.0,\n)\nclean = qv.clean_spread(spark, market.eua_curve, emissions_intensity=0.37)\nprint("clean spark spread (Dec-26):", clean.per_period[period], "EUR/MWh")`, `clean spark spread (Dec-26): -14.06 EUR/MWh`)}
  <h2 id="spread-option">2. Clean spark spread OPTION</h2><p>The right (not obligation) to run the plant that period. This is Kirk's approximation (heat rate != 1), with a strike that nets out variable O&amp;M plus the deterministic carbon cost so the priced optionality is on power vs. gas only.</p>${codeBlock(`strike = variable_cost + emissions_intensity * eua_forward\nrequest = qv.SpreadOptionRequest(\n    forward1=power_forward, forward2=gas_forward, strike=strike,\n    sigma1=0.38, sigma2=0.52, correlation=0.61,\n    time_to_expiry=0.4, discount_factor=discount_factor,\n    notional=1_000.0,\n)\noption = qv.price_spark_spread_option(request, heat_rate=2.0)`, `clean spark spread option premium: 2953.54 EUR\nmodel: Kirk (approximation; strike != 0)`)}
  <h2 id="tolling-position">3. The same underlying power, fuel, and carbon exposure represented through a richer tolling structure</h2><p>A <code>TollingAgreement</code> is priced by <code>DEFAULT_PRICERS</code> directly &mdash; no PPA-style pricer registration required. It is <strong>not</strong> the step-2 option re-quoted: the NPV differs (454.19 vs 2953.54 EUR) because the tolling is a richer representation of the same power/fuel/carbon exposure. Carbon enters the stochastic fuel+carbon leg here (with its own volatility and correlation) rather than a deterministic strike; the combined leg reuses the power volatility 0.38 (the "one volatility surface" convention) rather than the gas 0.52; and the horizon is the actual 0.463-year decision window, not the illustrative 0.40. <code>PlantConfig.emissions_intensity</code> is tCO2/MWh_fuel (multiplied by the heat rate), whereas the step-2 strike used 0.37 per MWh_power &mdash; so the tolling carries the larger, engineering-consistent carbon charge. <code>MarketData.vol_surfaces</code> / <code>correlations</code> supply the three-leg vol/correlation inputs.</p>${codeBlock(`tolling = qv.TollingAgreement(\n    plant=plant, power_commodity_id="EEX_PHELIX_DE",\n    fuel_commodity_id="TTF", eua_commodity_id="EUA",\n    schedule=qv.DeliverySchedule((period,)), capacity=1_000.0,\n)\nposition = qv.Position(instrument=tolling, position_id="plant-tolling-dec26")\nportfolio = qv.Portfolio((position,))\nvaluation = qv.value_portfolio(portfolio, market_data)\npriced = valuation.priced[0]`, `tolling position NPV: 454.19 EUR\nfuel (TTF) delta: -68.9488 EUR per EUR/MWh\nEUA delta: -25.511 EUR per EUR/MWh`)}
  <h2 id="hedge">4. Variance-minimizing hedge</h2><p>Hedge the position's gas/EUA exposure with traded TTF and EUA futures. <code>sigma_hh</code> and <code>sigma_ht</code> would be estimated from historical joint returns in production; here they are illustrative fixed numbers, not derived mechanically from the deltas above (which would make the optimal ratio trivially equal to delta).</p>${codeBlock(`sigma_hh = np.array([[4.00, 0.90], [0.90, 1.00]])  # TTF, EUA covariance (assumed)\nsigma_ht = np.array([-52.0, -14.0])                # covariance with position P&L (assumed)\nhedge_ratios = qv.variance_min_hedge(sigma_hh, sigma_ht)`, `hedge ratios (TTF futures, EUA futures): [-12.3511, -2.884]\n(position deltas were TTF -68.95 EUA -25.51)`)}
  <div class="admonition warning"><b>Kirk is an approximation</b><p>The spread-option premium above uses Kirk's approximation (exact at K=0, where it collapses to Margrabe). See the <a href="#/guide/validation">validation page</a> for the measured Kirk-vs-Monte-Carlo bias.</p></div>
`};

window.DOC_GUIDES['tutorial-ppa'] = {title:"Tutorial: renewable PPA to CFaR",description:"Degree-days to jointly-sampled generation/price scenarios, settle_ppa_frame with a floor and negative-price clause, and cash_flow_at_risk.",body:`
  <p>Full runnable script: <code>site/examples/verify_tutorial_ppa.py</code>. Crosses <code>quantvolt.market</code> (weather), <code>quantvolt.models.ppa_terms</code> (embedded floor and negative-price clause), <code>quantvolt.pricing.ppa</code> and <code>quantvolt.risk</code>.</p>
  <div class="admonition warning"><b>Sample jointly, not independently</b><p>Generation and price are sampled from ONE correlated shock per scenario (merit-order cannibalisation: high wind output depresses the price in the same hour). Sampling them independently would hide the exact downside CFaR is meant to measure. The scenario generator is illustrative and is not presented as a calibrated market forecast.</p></div>
  <h2 id="weather">1. Weather context</h2>${codeBlock(`from quantvolt.market import degree_days\n\nfeatures = degree_days(temperatures, base_celsius=15.0)`, `degree-day feature (day 1): {'location': 'North Sea', 'date': date(2026, 1, 1),\n  'temp_celsius': 2.0, 'hdd': 13.0, 'cdd': 0.0}`)}
  <h2 id="scenarios">2. A wind PPA with a floor and a negative-price clause</h2>${codeBlock(`contract = qv.PpaContract(\n    contract_id="wind-farm-ppa", bidding_zone="DE-LU",\n    fixed_price_per_mwh=55.0, start_utc=start, end_utc=end,\n    volume_basis=qv.PpaVolumeBasis.PAY_AS_PRODUCED,\n    terms=qv.PpaTerms(\n        price=qv.PpaPriceTerms(floor_price_per_mwh=30.0),\n        negative_price=qv.NegativePriceClause(\n            treatment=qv.NegativePriceTreatment.NO_COMPENSATION,\n            threshold_per_mwh=0.0,\n        ),\n    ),\n)\n# Jointly sample generation and price from one correlated shock (rho = -0.6).\nz = rng.standard_normal((n_scenarios, 2))\ngeneration_shock = z[:, 0]\nprice_shock = rho * z[:, 0] + np.sqrt(1.0 - rho**2) * z[:, 1]`, `scenario count: 5000\nmin / max sampled price: -108.33 / 210.46\nnegative-price scenario share: 0.1088`)}
  <h2 id="settlement">3. Settle each scenario (floor and negative-price clause visible)</h2>${codeBlock(`ledger = qv.settle_ppa_frame(\n    contract, data, imbalance_policy=qv.MissingImbalancePricePolicy.USE_SPOT\n)\nnet_cashflow = ledger["net_cashflow"].item()`, `cash flow, generation=400 MWh, price=10 EUR/MWh (floor binds): 22000.0\ncash flow, generation=400 MWh, price=-20 EUR/MWh (no-compensation clause binds): 0.0`)}
  <h2 id="cfar">4. Cash-Flow-at-Risk over the scenario set</h2>${codeBlock(`cfar = qv.cash_flow_at_risk(\n    cashflow_model, scenarios, horizon=1, seed=7,\n    consistency={"generation": "same correlated shock as price"},\n    confidence_level=0.95,\n)`, `expected cash flow: 17736.64\np5 cash flow: 0.0\nCFaR 95: 17736.64`)}
  <p>The floor does not fully protect against downside here: the negative-price no-compensation clause suspends the fixed leg outright whenever spot is strictly below 0 EUR/MWh, and that happens on 10.9% of scenarios &mdash; enough that the 5th percentile of the cash-flow distribution sits exactly at the resulting zero cash flow, making CFaR 95 numerically equal to the expected cash flow.</p>
`};

window.DOC_GUIDES['tutorial-storage'] = {title:"Tutorial: storage intrinsic to hedge",description:"A seasonal gas curve to storage_intrinsic, seeded storage_value extrinsic, and a forward hedge built from the intrinsic schedule.",body:`
  <p>Full runnable script: <code>site/examples/verify_tutorial_storage.py</code>. Crosses <code>curves</code> (the seasonal TTF curve from <code>shared_setup.seasonal_gas_curve()</code>), <code>quantvolt.assets</code> and <code>portfolio</code>.</p>
  <h2 id="curve">1. A seasonal 12-month curve</h2>${codeBlock(`SEASONAL_GAS_PRICES = (20.0, 19.0, 21.0, 24.0, 27.0, 30.0, 32.0, 31.0, 28.0, 25.0, 22.0, 20.0)\n\ndef seasonal_gas_curve():\n    periods = [qv.DeliveryPeriod(2027, month) for month in range(1, 13)]\n    nodes = tuple(\n        qv.CurveNode(period, price, "observed")\n        for period, price in zip(periods, SEASONAL_GAS_PRICES, strict=True)\n    )\n    return qv.ForwardCurve(commodity=TTF, market_date=MARKET_DATE, nodes=nodes)`, `Cheap in summer (20 EUR/MWh), expensive in winter (32 EUR/MWh peak)`)}
  <h2 id="intrinsic">2. Deterministic intrinsic value</h2>${codeBlock(`model = StorageModel(\n    min_inventory=0.0, max_inventory=100.0,\n    initial_inventory=50.0, terminal_inventory=50.0,\n    injection_rate=lambda inventory: 40.0,\n    withdrawal_rate=lambda inventory: 40.0,\n    injection_cost=0.05, withdrawal_cost=0.05,\n    injection_loss=0.01, withdrawal_loss=0.01,\n    carry_cost=0.02, terminal_penalty=None,\n)\nintrinsic = storage_intrinsic(model, curve, grid_steps=100)`, `intrinsic value: 1066.0\ninjection schedule (MWh): [10.0, 40.0, 0, 0, 0, 0, 0, 0, 0, 0, 10.0, 40.0]\nwithdrawal schedule (MWh): [0, 0, 0, 0, 0, 20.0, 40.0, 40.0, 0, 0, 0, 0]\ninventory path: [50.0, 60.0, 100.0, 100.0, 100.0, 100.0, 80.0, 40.0, 0, 0, 0, 10.0, 50.0]`)}
  <h2 id="extrinsic">3. Seeded extrinsic (re-optimisation) value</h2>${codeBlock(`factor_model = StorageFactorModel(volatility=0.5, dt=1.0 / 12.0, path_count=3_000)\ntotal = storage_value(model, curve, factor_model, seed=7, grid_steps=100)`, `total value: 1066.15\nintrinsic (from storage_value): 1066.0\nextrinsic value: 0.1515\nextrinsic standard error: 0.2994`)}
  <div class="admonition warning"><b>This extrinsic estimate is statistically indistinguishable from zero</b><p>The extrinsic estimate 0.1515 is <em>smaller than its own Monte Carlo standard error</em> (0.2994). Its ~95% confidence interval is <code>0.1515 &plusmn; 1.96 &times; 0.2994 = [-0.44, 0.74]</code> &mdash; it straddles zero. On this deep, near-monotone seasonal curve the intrinsic schedule already captures essentially all the value, so the true extrinsic is near zero and 0.1515 is Monte Carlo noise. Re-running with more paths confirms it: at 12,000 paths the estimate falls to 0.0512 (SE 0.0681, CI [-0.08, 0.18]) and at 48,000 paths it converges to 0.0000 (SE 0.0000, both to 4 dp). Do not report this extrinsic value as a P&amp;L number; increase the path count or add variance reduction until the standard error is small relative to the estimate before relying on any extrinsic figure.</p></div>
  <p><strong>What the intrinsic-schedule hedge does and does not cover.</strong> The forward book in step 4 replicates the <em>intrinsic</em> injection/withdrawal schedule at the curve's own prices. It hedges that fixed schedule only. It does <em>not</em> hedge the extrinsic optionality (the value of re-optimising as spot evolves), the path-dependent re-optimisation itself, or policy/curve changes between valuation and delivery. The store's terminal condition here is a <em>hard</em> target (<code>terminal_penalty=None</code>): the schedule must finish at exactly <code>terminal_inventory = 50.0</code> MWh. A soft target (<code>terminal_penalty &ge; 0</code>) would instead subtract <code>terminal_penalty &times; |inventory_end - terminal_inventory|</code> and let the optimiser leave the store off-target.</p>
  <h2 id="forward-hedge">4. Forward hedge built from the intrinsic schedule (both legs)</h2><p>Buy a future (<code>side=OptionSide.LONG</code>) in every month with net injection and sell one (<code>side=OptionSide.SHORT</code>) in every month with net withdrawal, each at that month's own curve price. Direction is carried by <code>FuturesContract.side</code>, never by a signed notional: notional stays strictly positive and the short withdrawal leg prices to the exact negation of the same long position (the portfolio pricer sign-flips npv and delta). Because <code>contract_price</code> equals the curve's own forward, every position's day-one NPV is exactly <code>&plusmn; DF &times; (forward &minus; contract_price) &times; notional == 0</code> &mdash; these trades <strong>replicate</strong> the schedule's forward-locked purchase and sale; they do not add extra valuation today.</p>${codeBlock(`for period, injected, withdrawn in zip(\n    periods, intrinsic.injection, intrinsic.withdrawal, strict=True\n):\n    if injected >= 1e-9:\n        side, notional, leg = qv.OptionSide.LONG, injected, "buy"\n    elif withdrawn >= 1e-9:\n        side, notional, leg = qv.OptionSide.SHORT, withdrawn, "sell"\n    else:\n        continue\n    future = qv.FuturesContract(\n        commodity=TTF, delivery_period=period,\n        contract_price=curve.price_at(period), notional=notional, side=side,\n    )\n    positions.append(qv.Position(instrument=future, position_id=f"storage-hedge-{leg}-{period}"))\nvaluation = qv.value_portfolio(qv.Portfolio(tuple(positions)), market_data)`, `hedge positions: 7\nhedge book total NPV (must be ~0: transacted at the curve's own forward): 0.0`)}
`};

// Rewrite the end-to-end page into a map with teaser links to the three standalone tutorials.
window.DOC_GUIDES['end-to-end'].body = `
  <h2 id="tutorial-map">Tutorial map</h2><p>Three of the workflows below are complete, standalone, runnable tutorials with every output captured from an actual script run; the rest remain compact cross-references.</p>
  <div class="topic-grid">
    <a href="#/guide/tutorial-spark"><b>Spark spread to hedge</b><span>Power/gas/EUA curves &rarr; clean spark spread option &rarr; native tolling position &rarr; variance-min hedge.</span><i>&rarr;</i></a>
    <a href="#/guide/tutorial-ppa"><b>Renewable PPA to CFaR</b><span>Degree-days &rarr; jointly-sampled scenarios &rarr; settle_ppa_frame with a floor + negative-price clause &rarr; CFaR.</span><i>&rarr;</i></a>
    <a href="#/guide/tutorial-storage"><b>Storage intrinsic to hedge</b><span>Seasonal curve &rarr; storage_intrinsic &rarr; seeded storage_value extrinsic &rarr; forward hedge from the schedule.</span><i>&rarr;</i></a>
  </div>
  <table><thead><tr><th>Workflow</th><th>Modules crossed</th><th>Primary result</th></tr></thead><tbody><tr><td>Quotes to VaR</td><td>models &rarr; curves &rarr; pricing &rarr; portfolio &rarr; risk</td><td>Valued portfolio and named loss measures</td></tr><tr><td>Forward simulation</td><td>curvemodels &rarr; portfolio &rarr; risk</td><td>Monte Carlo VaR and named stresses</td></tr><tr><td>Offline replay</td><td>data &rarr; models &rarr; serialization</td><td>Auditable provider-independent rerun</td></tr></tbody></table>
  <h2 id="curve-to-var">Quotes &rarr; curve &rarr; instrument &rarr; portfolio &rarr; VaR</h2><div class="dependency-flow"><code>MarketQuote[]</code><span>&rarr;</span><code>ForwardCurve</code><span>&rarr;</span><code>EnergyFuture</code><span>&rarr;</span><code>Portfolio</code><span>&rarr;</span><code>RiskReport</code></div>${codeBlock(`import numpy as np\nimport quantvolt as qv\n\n# shared_setup exports example_market() + the calendar/commodity constants.\nfrom shared_setup import MARKET_DATE, OCT_26, DEC_26, TTF, example_market\n\nmarket = example_market()\nttf_curve, discount_curve = market.ttf_curve, market.discount_curve\n\n# A tiny two-future book with stable position IDs.\nportfolio = qv.Portfolio((\n    qv.Position(qv.FuturesContract(\n        commodity=TTF, delivery_period=OCT_26,\n        contract_price=ttf_curve.price_at(OCT_26), notional=10.0,\n        side=qv.OptionSide.LONG), position_id="ttf-fut-oct26"),\n    qv.Position(qv.FuturesContract(\n        commodity=TTF, delivery_period=DEC_26,\n        contract_price=ttf_curve.price_at(DEC_26) - 1.0, notional=5.0,\n        side=qv.OptionSide.LONG), position_id="ttf-fut-dec26"),\n))\n\nvaluation = qv.value_portfolio(portfolio, qv.MarketData(\n    valuation_date=MARKET_DATE,\n    forward_curves={"TTF": ttf_curve},\n    discount_curve=discount_curve,\n))\n\n# 2 factors: (TTF, Oct-26) and (TTF, Dec-26), in that flattened order.\nscenario_matrix = np.array([\n    [+2.0, +1.5],   # both months up\n    [-3.0, -2.5],   # both months down\n    [+1.0, -4.0],   # front up, back sharply down\n])\nrisk = qv.RiskEngine().compute_risk(list(valuation.priced), scenario_matrix)\n\nfor priced in valuation.priced:\n    print(priced.position.position_id, round(priced.npv, 2))\nprint("VaR 95", round(risk.var_95, 2))\nprint("VaR 99", round(risk.var_99, 2))\nprint("CVaR 97.5", round(risk.cvar_975, 2))`, `ttf-fut-oct26 0.0\nttf-fut-dec26 4.94\nVaR 95 38.92\nVaR 99 41.5\nCVaR 97.5 42.15`)}
  <h2 id="reproducibility">Reproducibility contract</h2>${codeBlock(`from quantvolt.data import restore, snapshot\n\npayload = snapshot(ttf_curve)\nreplayed_curve = restore(payload)\nassert replayed_curve == ttf_curve\n\n# your_seeded_analysis is illustrative: substitute your own seeded call.\n# Same inputs, seed, QuantVolt version, architecture and native build\n# reproduce both estimate and diagnostics.\nfirst = your_seeded_analysis(curve=replayed_curve, seed=42)\nsecond = your_seeded_analysis(curve=replayed_curve, seed=42)\nassert first == second`, `frozen input snapshot + explicit seed + checked output\n= provider-independent reproducible analysis`)}<p>Checked examples live in <code>site/examples/</code>. Run the foundation, pricing, PPA, research and tutorial verification files after changing public signatures or rendered outputs.</p>
`;
